var documenterSearchIndex = {"docs":
[{"location":"generated/muca_OU/#Large-Deviations-of-the-Ornstein–Uhlenbeck-Process","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Large Deviations of the Ornstein–Uhlenbeck Process","text":"The Ornstein–Uhlenbeck (OU) process is a continuous-time stochastic process with mean-reverting drift:\n\ndx_t = theta(mu - x_t)dt + sigmadW_t\n\nwhere mu is the long-time mean, theta the inverse relaxation timescale, sigma = sqrt2D the noise amplitude, and dW_t sim mathcalN(0 dt) a Wiener increment.\n\nThe terminal value x(T) is Gaussian with known mean and variance, providing an exact reference against which we validate three sampling strategies: direct sampling, biased Metropolis, and multicanonical iteration.\n\nusing Random, Distributions, StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots, ProgressMeter","category":"section"},{"location":"generated/muca_OU/#Parameters","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Parameters","text":"μ, D, θ  = 0.0, 1.0, 1.0\ndt, T, x0 = 0.1, 10.0, 0.0\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\nn_direct   = CI_MODE ? 1_000    : 100_000\nn_therm    = CI_MODE ? 100      : 10_000\nn_metro    = CI_MODE ? 1_000    : 1_000_000\nn_muca     = CI_MODE ? 1_000    : 10_000_000\nn_iter     = CI_MODE ? 3        : 10\nn_iter_steps = CI_MODE ? 1_000  : 5_000_000;\n# exact terminal distribution (see Wikipedia: OU process)\nmean_T = x0 * exp(-T*θ) + μ * (1 - exp(-T*θ))\nvar_T  = θ < 1e-6 ? 2*D*T : D/θ * (1 - exp(-2*T*θ))\nstd_T  = sqrt(var_T)\npdf_T  = Normal(mean_T, std_T)\n\nbins_T    = (mean_T - 10*std_T) : (std_T/10) : (mean_T + 10*std_T)\ncenters_T = collect(bins_T[1:end-1] .+ diff(collect(bins_T))./2)\nlogpdf_T  = logpdf.(pdf_T, centers_T)\n\nprintln(\"Terminal distribution: mean = $(mean_T),  std = $(round(std_T; digits=3))\")","category":"section"},{"location":"generated/muca_OU/#Trajectory-system","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Trajectory system","text":"The state is a full discretised trajectory dW_t of Wiener increments. Each update proposes a change to one randomly chosen increment, accepts it under the Gaussian prior (Metropolis-within-Gibbs), then accepts or rejects based on the terminal value x(T) via the sampling algorithm.\n\nmutable struct OUTrajectory\n    ts        :: Vector{Float64}\n    xs        :: Vector{Float64}\n    dWs       :: Vector{Float64}\n    tmp_xs    :: Vector{Float64}\n    tmp_dWs   :: Vector{Float64}\n    logpdf_dW :: Function\n    μ :: Float64;  σ :: Float64\n    θ :: Float64;  dt :: Float64\n    function OUTrajectory(rng; x0=0.0, μ=0.0, D=1.0, θ=1.0, dt=0.1, T=10.0)\n        N    = round(Int, T/dt) + 1\n        σ    = sqrt(2*D)\n        dist = Normal(0, sqrt(dt))\n        dWs  = rand(rng, dist, N)\n        xs   = zeros(N)\n        ts   = collect(0:dt:(N-1)*dt)\n        sys  = new(ts, xs, dWs, zeros(N), zeros(N),\n                   x -> logpdf(dist, x), μ, σ, θ, dt)\n        sys.xs[1] = x0\n        integrate!(sys)\n        return sys\n    end\nend\n\n@inline function integrate!(sys::OUTrajectory, r::UnitRange{Int}=1:0)\n    r = isempty(r) ? (1:length(sys.xs)) : r\n    x = sys.xs[first(r)]\n    for i in first(r):last(r)-1\n        x += sys.θ*(sys.μ - x)*sys.dt + sys.σ*sys.dWs[i]\n        sys.xs[i+1] = x\n    end\nend\n\nx_T(sys::OUTrajectory) = sys.xs[end]\n\nfunction update!(sys::OUTrajectory, alg::AbstractImportanceSampling; δ=0.5)\n    idx    = rand(alg.rng, 1:length(sys.dWs))\n    dW_old = sys.dWs[idx]\n    dW_new = dW_old + δ * (2*rand(alg.rng) - 1)\n    # accept under Gaussian prior first\n    if rand(alg.rng) < exp(sys.logpdf_dW(dW_new) - sys.logpdf_dW(dW_old))\n        sys.tmp_xs[idx:end]  .= sys.xs[idx:end]\n        sys.tmp_dWs[idx:end] .= sys.dWs[idx:end]\n        sys.dWs[idx] = dW_new\n        integrate!(sys, idx:length(sys.xs))\n        if !accept!(alg, sys.xs[end], sys.tmp_xs[end])\n            sys.xs[idx:end]  .= sys.tmp_xs[idx:end]\n            sys.dWs[idx:end] .= sys.tmp_dWs[idx:end]\n        end\n    else\n        alg.steps += 1\n    end\nend\n\n# visualise a single trajectory\nsys0 = OUTrajectory(MersenneTwister(1234); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nplot(sys0.ts, sys0.xs; label=nothing, xlabel=\"Time\", ylabel=\"x\",\n     title=\"Single OU trajectory\", size=(700, 220), margin=5Plots.mm)","category":"section"},{"location":"generated/muca_OU/#Direct-sampling","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Direct sampling","text":"We draw 10^5 independent trajectories and record x(T) as a reference.\n\ndirect_samples = [OUTrajectory(MersenneTwister(i); x0=x0, μ=μ, D=D, θ=θ,\n                               dt=dt, T=T).xs[end] for i in 1:n_direct]\nhist_direct = normalize(fit(Histogram, direct_samples, bins_T); mode=:pdf)\n\nplot(hist_direct; st=:bar, linewidth=0, alpha=0.6,\n     label=\"Direct samples\", xlabel=\"x(T)\", ylabel=\"Density\",\n     title=\"Terminal distribution vs exact\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_T, pdf.(pdf_T, centers_T); lw=2, color=:black, ls=:dash, label=\"Exact\")","category":"section"},{"location":"generated/muca_OU/#Importance-sampling-with-Metropolis","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Importance sampling with Metropolis","text":"A biasing field beta exponentially enhances trajectories ending at large (beta  0) or small (beta  0) values of x(T), giving direct access to the tails of the distribution.\n\nfunction run_metropolis(; β=0.0)\n    sys  = OUTrajectory(MersenneTwister(123); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\n    alg  = Metropolis(MersenneTwister(42); β=β)\n    meas_ts   = Measurements([:x_T => x_T => Float64[]], interval=100)\n    meas_hist = Measurements([:x_T => x_T => fit(Histogram, [], bins_T)], interval=1)\n    for _ in 1:n_therm;  update!(sys, alg); end\n    for i in 1:n_metro\n        update!(sys, alg)\n        measure!(meas_hist, sys, i)\n        measure!(meas_ts,   sys, i)\n    end\n    println(\"β = $(β):  acceptance = \", round(acceptance_rate(alg); digits=3))\n    return meas_ts, meas_hist, sys\nend\n\nβs      = [0.0, 3.0, 6.0]\nresults = Dict(β => run_metropolis(β=β) for β in βs)\n\n# time series — shows how β shifts the explored region\np_ts = plot(xlabel=\"Iteration\", ylabel=\"x(T)\", title=\"Time series\",\n            legend=:topleft, size=(600, 220), margin=5Plots.mm)\nfor β in βs\n    plot!(p_ts, results[β][1][:x_T].data; label=\"β=$β\", lw=1)\nend\np_ts","category":"section"},{"location":"generated/muca_OU/#Terminal-distributions-under-biasing","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Terminal distributions under biasing","text":"Each beta samples a different part of the tail. Together they cover the full distribution including the exponentially rare large-x(T) events.\n\np_dist = plot(centers_T, pdf.(pdf_T, centers_T);\n              lw=2, color=:black, ls=:dash, label=\"Exact\",\n              xlabel=\"x(T)\", ylabel=\"Density\",\n              title=\"Biased distributions\", size=(600, 250), margin=5Plots.mm)\nfor β in βs\n    w    = results[β][2][:x_T].data.weights\n    norm = sum(w) * step(bins_T)\n    plot!(p_dist, centers_T, w ./ norm; lw=2, label=\"β=$β\")\nend\np_dist","category":"section"},{"location":"generated/muca_OU/#Biased-trajectories","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Biased trajectories","text":"Larger beta shifts the ensemble of trajectories toward systematically higher terminal values, revealing the rare fluctuation pathways.\n\np_traj = plot(xlabel=\"Time\", ylabel=\"x\", title=\"Typical trajectories per β\",\n              size=(700, 260), margin=5Plots.mm)\np_dW   = plot(xlabel=\"Time\", ylabel=\"dW\", title=\"Wiener increments\",\n              size=(700, 260), margin=5Plots.mm)\nfor β in βs\n    sys = results[β][3]\n    plot!(p_traj, sys.ts, sys.xs;  label=\"β=$β\")\n    plot!(p_dW,   sys.ts, sys.dWs; label=\"β=$β\")\n    println(\"β=$β:  mean x = \", round(mean(sys.xs); digits=3),\n                   \"  mean dW = \", round(mean(sys.dWs); digits=3))\nend\nplot(p_traj, p_dW; layout=(2,1), size=(700, 420), margin=5Plots.mm)","category":"section"},{"location":"generated/muca_OU/#Multicanonical-sampling-—-flat-histogram","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Multicanonical sampling — flat histogram","text":"With flat weights the algorithm samples x(T) uniformly across the full support, independently of the shape of the distribution.\n\nsys_muca0  = OUTrajectory(MersenneTwister(123); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nalg_muca0  = Multicanonical(MersenneTwister(100), BinnedObject(bins_T, 0.0))\nmeas_muca0 = Measurements([:x_T => x_T => fit(Histogram, [], bins_T)], interval=1)\n\nfor _ in 1:n_therm;  update!(sys_muca0, alg_muca0); end\nfor i in 1:n_muca;   update!(sys_muca0, alg_muca0); measure!(meas_muca0, sys_muca0, i); end\nprintln(\"MUCA (flat):  acceptance = \", round(acceptance_rate(alg_muca0); digits=3))\n\nw0   = meas_muca0[:x_T].data.weights\nnorm0 = sum(w0) * step(bins_T)\nplot(centers_T, w0 ./ norm0; lw=2, label=\"MUCA (flat)\",\n     xlabel=\"x(T)\", ylabel=\"Density\",\n     title=\"Flat-weight multicanonical\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_T, pdf.(pdf_T, centers_T); lw=2, color=:black, ls=:dash, label=\"Exact\")","category":"section"},{"location":"generated/muca_OU/#Multicanonical-iteration","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Multicanonical iteration","text":"Starting from flat weights, the algorithm iteratively learns the log-DOS. Linear boundary tails prevent the chain escaping the binned region.\n\nsys_iter = OUTrajectory(MersenneTwister(42); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nalg_iter = Multicanonical(MersenneTwister(42), BinnedObject(bins_T, 0.0))\n\nn_iter      = 10\niter_hists  = typeof(ensemble(alg_iter).histogram)[]\niter_lws    = typeof(logweight(alg_iter))[]\niter_accept = Float64[]\n\nx_left  = first(bins_T) + std_T\nx_right = last(bins_T)  - std_T\ncs      = get_centers(logweight(alg_iter))\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:n_iter\n    for _ in 1:n_therm;    update!(sys_iter, alg_iter; δ=0.5); end\n    reset!(alg_iter)\n    for _ in 1:n_iter_steps; update!(sys_iter, alg_iter; δ=0.5); end\n\n    MonteCarloX.update!(ensemble(alg_iter); mode=:simple)\n\n    # reapply linear boundary tails\n    set!(logweight(alg_iter), (first(cs), x_left),\n         x -> logweight(alg_iter)(x_left)  + (x - x_left)  * 2.0)\n    set!(logweight(alg_iter), (x_right, last(cs)),\n         x -> logweight(alg_iter)(x_right) - (x - x_right) * 2.0)\n\n    push!(iter_hists,  deepcopy(ensemble(alg_iter).histogram))\n    push!(iter_lws,    deepcopy(logweight(alg_iter)))\n    push!(iter_accept, acceptance_rate(alg_iter))\nend\n\nplot(iter_accept; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     title=\"Convergence of acceptance rate\", label=nothing,\n     size=(600, 220), margin=5Plots.mm)","category":"section"},{"location":"generated/muca_OU/#Plotting-convergence-of-histogram-and-log-DOS","page":"Multicanonical: Ornstein-Uhlenbeck","title":"Plotting convergence of histogram and log-DOS","text":"Each iteration refines the log-DOS estimate toward the exact reference.\n\nfunction plot_muca_convergence(hists, lws; xlabel=\"x(T)\")\n    n    = length(hists)\n    cols = palette(:viridis, max(n,2))[1:n]\n    i0   = searchsortedlast(centers_T, 0.0)\n\n    p1 = plot(xlabel=xlabel, ylabel=\"Counts\", title=\"Histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, centers_T, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=xlabel, ylabel=\"-log w\", title=\"Log-DOS vs exact\",\n              legend=:topright)\n    for i in 1:n\n        w = -lws[i].values .+ lws[i](0.0)\n        plot!(p2, centers_T, w; lw=2, color=cols[i], label=\"\")\n    end\n    plot!(p2, centers_T, logpdf_T .- logpdf_T[i0];\n          lw=2, color=:black, ls=:dash, label=\"Exact\")\n\n    return plot(p1, p2; layout=(1,2), size=(900, 280), margin=4Plots.mm)\nend\n\nplot_muca_convergence(iter_hists, iter_lws)\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"systems/#Systems-and-Model-Packages","page":"Systems","title":"Systems and Model Packages","text":"MonteCarloX keeps systems external on purpose. The framework provides algorithms; companion packages provide concrete models.","category":"section"},{"location":"systems/#Why-this-split-helps","page":"Systems","title":"Why this split helps","text":"algorithm implementations stay generic\nmodel packages can evolve independently\nthe same sampler can be reused across many domains","category":"section"},{"location":"systems/#Example:-SpinSystems-with-Ising","page":"Systems","title":"Example: SpinSystems with Ising","text":"using Random\nusing MonteCarloX\nusing SpinSystems\n\nrng = MersenneTwister(123)\nsys = Ising([16, 16], J=1.0, periodic=true)\ninit!(sys, :random, rng=rng)\nalg = Metropolis(rng; β=0.44)\n\nfor _ in 1:100_000\n    spin_flip!(sys, alg)\nend\n\nprintln(\"E  = \", energy(sys))\nprintln(\"|M| = \", magnetization(sys))","category":"section"},{"location":"systems/#What-a-custom-model-package-should-implement","page":"Systems","title":"What a custom model package should implement","text":"At minimum:\n\na concrete system type (AbstractSystem subtype)\nobservable functions for analysis\nupdate methods that call MonteCarloX primitives (accept!, etc.)\ninitialization utilities (init! pattern)\n\nThis is usually enough to plug your model into measurement and algorithm workflows immediately.","category":"section"},{"location":"generated/kmc_poisson/#Poisson-Processes-via-Kinetic-Monte-Carlo","page":"Gillespie: Poisson Process","title":"Poisson Processes via Kinetic Monte Carlo","text":"A Poisson process is the simplest continuous-time stochastic process: events occur independently at a given rate. This example builds homogeneous and inhomogeneous Poisson processes directly from the MonteCarloX.jl kinetic Monte Carlo primitives, showing both the high-level step! interface and the low-level next_time / next_event building blocks.\n\nusing Random, StatsBase, BenchmarkTools, Plots\nusing MonteCarloX","category":"section"},{"location":"generated/kmc_poisson/#Homogeneous-Poisson-process","page":"Gillespie: Poisson Process","title":"Homogeneous Poisson process","text":"A constant rate lambda gives exponentially distributed inter-arrival times with mean 1lambda. We model this as a single-channel KMC process and validate the inter-arrival statistics.\n\nλ = 1.2\nT = 10.0\n\nalg = Gillespie(MersenneTwister(7))\narrivals = Float64[]\n\nwhile alg.time < T\n    t_new, event = step!(alg, [λ])\n    push!(arrivals, t_new)\nend\n\ninter_arrival = diff([0.0; arrivals])\nprintln(\"Events          : \", alg.steps)\nprintln(\"Mean inter-arrival — simulation : \", round(mean(inter_arrival); digits=3))\nprintln(\"Mean inter-arrival — exact      : \", round(1/λ;                 digits=3))","category":"section"},{"location":"generated/kmc_poisson/#Benchmark:-step!-vs-raw-randexp","page":"Gillespie: Poisson Process","title":"Benchmark: step! vs raw randexp","text":"The step! interface adds minimal overhead over a bare exponential draw. We compare both to quantify the cost of the KMC bookkeeping.\n\nprintln(\"\\nBenchmark: step! interface\")\n@btime begin\n    alg = Gillespie(MersenneTwister(7))\n    arr = Float64[]\n    while alg.time < $T\n        t_new, _ = step!(alg, [$λ])\n        push!(arr, t_new)\n    end\nend\n\nprintln(\"Benchmark: raw randexp\")\n@btime begin\n    rng = MersenneTwister(7)\n    t   = 0.0\n    arr = Float64[]\n    while t < $T\n        t += randexp(rng) / $λ\n        push!(arr, t)\n    end\nend","category":"section"},{"location":"generated/kmc_poisson/#Inhomogeneous-Poisson-process-via-thinning","page":"Gillespie: Poisson Process","title":"Inhomogeneous Poisson process via thinning","text":"When the rate varies with time, exact sampling uses thinning (Lewis & Shedler 1979): propose candidate times from a dominating homogeneous process at rate lambda_textmax, then accept each candidate with probability  lambda(t)  lambda_textmax. MonteCarloX.jl implements this internally when step! receives a Function as its event source — the function is called as rates(t) at the proposed time to evaluate acceptance.\n\nHere we have two channels with sinusoidal rates:\n\nlambda_1(t) = 06 + 03sin(t) qquad lambda_2(t) = 07 + 02cos(t)\n\nrate_fn(t)       = [0.6 + 0.3*sin(t),  0.7 + 0.2*cos(t)]\nrate_max         = [1.0, 1.0]           ## dominating rates per channel\n\nalg    = Gillespie(MersenneTwister(21))\nT      = 20.0\ncounts = zeros(Int, 2)\nevent_times = Float64[]\n\nwhile alg.time < T\n    t_new, event = step!(alg, rate_fn)\n    isnothing(event) && break\n    counts[event] += 1\n    push!(event_times, t_new)\nend\n\nprintln(\"Total events    : \", alg.steps)\nprintln(\"Channel counts  : \", counts)\nprintln(\"Final time      : \", round(alg.time; digits=3))","category":"section"},{"location":"generated/kmc_poisson/#Visualisation","page":"Gillespie: Poisson Process","title":"Visualisation","text":"The event time series shows the two channels interleaved. # The marginal inter-arrival distribution should be approximately exponential with a rate equal to the time-averaged total rate.\n\n# inter-arrival histogram vs exponential fit\nmean_rate   = mean(sum(rate_fn(t)) for t in event_times)\ninter_inhom = diff([0.0; event_times])\n\np1 = histogram(inter_inhom; bins=30, normalize=:pdf, alpha=0.6,\n               label=\"Inter-arrival\", xlabel=\"Δt\", ylabel=\"Density\",\n               title=\"Inhomogeneous inter-arrivals\")\nts = range(0, maximum(inter_inhom); length=200)\nplot!(p1, ts, mean_rate .* exp.(-mean_rate .* ts);\n      lw=2, color=:black, ls=:dash, label=\"Exp(mean rate)\")\n\nt_grid = range(0, T; length=300)\np2 = plot(t_grid, [r[1] for r in rate_fn.(t_grid)]; lw=2, label=\"λ₁(t)\",\n          xlabel=\"Time\", ylabel=\"Rate\", title=\"Time-varying rates\")\nplot!(p2, t_grid, [r[2] for r in rate_fn.(t_grid)]; lw=2, label=\"λ₂(t)\")\nvline!(p2, event_times[findall(x -> x == 1, counts)]; alpha=0.15, color=:gray, label=\"\")\n\nplot(p1, p2; layout=(1,2), size=(900, 280), margin=5Plots.mm)\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"generated/muca_Ising2D/#Multicanonical-sampling-of-the-2D-Ising-model","page":"Multicanonical sampling: Ising 2D","title":"Multicanonical sampling of the 2D Ising model","text":"Multicanonical (muca) sampling iteratively refines energy weights to produce a flat histogram, enabling efficient sampling across the phase transition. We validate against the exact density of states by Beale (1996).\n\nusing Random, StatsBase, Plots\nusing MonteCarloX, SpinSystems, MPI\n\nMPI.Initialized() || MPI.Init()","category":"section"},{"location":"generated/muca_Ising2D/#Parameters","page":"Multicanonical sampling: Ising 2D","title":"Parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nL             = 8;\nn_iter        = CI_MODE ? 3 : 10;\nsweeps_therm  = CI_MODE ? 100 : 1_000;\nsweeps_record = CI_MODE ? 1_000 : 100_000;\nnothing #hide","category":"section"},{"location":"generated/muca_Ising2D/#Validation-and-visualization","page":"Multicanonical sampling: Ising 2D","title":"Validation and visualization","text":"The exact log-density of states for the Ltimes L Ising model (Beale 1996) serves as reference. rmse_exact quantifies convergence per iteration and plot_muca visualizes the histogram, estimated log-DOS against the exact reference, and the RMSE convergence.\n\nexact_logdos          = logdos_exact_ising2D(L)\nexact_logdos.values .-= exact_logdos[0]\nmask                  = .!isnan.(exact_logdos.values)\n\nfunction rmse_exact(lw)\n    est = -deepcopy(lw.values) .+ lw[0]\n    return sqrt(mean((est[mask] .- exact_logdos.values[mask]).^2))\nend\n\nfunction plot_muca(hists::Vector{BinnedObject}, lws::Vector{BinnedObject}; title=\"\")\n    n        = length(hists)\n    cols     = palette(:viridis, max(n, 2))[1:n]\n    energies = get_centers(hists[1])\n    i0       = findfirst(==(0), energies)\n\n    p1 = plot(xlabel=\"E\", ylabel=\"counts\", title=\"$(title) histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, energies, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=\"E\", ylabel=\"-log w(E)\", title=\"$(title) log-DOS\", legend=false)\n    for i in 1:n\n        w = -deepcopy(lws[i].values)\n        i0 !== nothing && (w .-= w[i0])\n        plot!(p2, energies, w; lw=2, color=cols[i])\n    end\n    ref = Float64.(exact_logdos.values)\n    i0 !== nothing && isfinite(ref[i0]) && (ref .-= ref[i0])\n    plot!(p2, energies, ref; lw=2, color=:black, label=\"exact\")\n\n    rmse = rmse_exact.(lws)\n    p3   = scatter(1:n, rmse; ms=4, color=:steelblue,\n                   xlabel=\"iter\", ylabel=\"RMSE\",\n                   title=\"$(title) convergence\",\n                   legend=false, yscale=:log10)\n\n    return plot(p1, p2, p3; layout=(1,3), size=(980,260), margin=4Plots.mm), rmse\nend","category":"section"},{"location":"generated/muca_Ising2D/#Serial-MUCA","page":"Multicanonical sampling: Ising 2D","title":"Serial MUCA","text":"A single Markov chain accumulates the energy histogram. After each iteration weights are updated via the Wang-Landau rule until the histogram flattens.\n\nsys = IsingLatticeOptim(L, L)\ninit!(sys, :random, rng=Xoshiro(1000))\nalg = Multicanonical(Xoshiro(1000), get_centers(exact_logdos))\n\nserial_hists, serial_lws = BinnedObject[], BinnedObject[]\nfor _ in 1:n_iter\n    for _ in 1:(sweeps_therm  * length(sys.spins)); spin_flip!(sys, alg); end\n    reset!(alg)\n    for _ in 1:(sweeps_record * length(sys.spins)); spin_flip!(sys, alg); end\n    update!(ensemble(alg); mode=:simple)\n    push!(serial_hists, deepcopy(alg.ensemble.histogram))\n    push!(serial_lws,   deepcopy(alg.ensemble.logweight))\nend\n\nplt, rmse = plot_muca(serial_hists, serial_lws; title=\"Serial\")\nprintln(\"Serial RMSE = \", round(last(rmse), digits=4))\nplt","category":"section"},{"location":"generated/muca_Ising2D/#Parallel-MUCA-with-MPI","page":"Multicanonical sampling: Ising 2D","title":"Parallel MUCA with MPI","text":"Each rank runs an independent chain over 1/nranks of the sweeps. After each iteration histograms are merged onto rank 0, weights updated and broadcast back. With a single rank (VS Code/REPL) the result is identical to the serial version above.\n\npmuca = ParallelMulticanonical(MPI.COMM_WORLD, root=0)\nsys   = IsingLatticeOptim(L, L)\ninit!(sys, :random, rng=Xoshiro(1000 + pmuca.rank))\nalg   = Multicanonical(Xoshiro(1000 + pmuca.rank), get_centers(exact_logdos))\n\nmpi_hists, mpi_lws = BinnedObject[], BinnedObject[]\nfor _ in 1:n_iter\n    for _ in 1:(sweeps_therm  * length(sys.spins));              spin_flip!(sys, alg); end\n    reset!(alg)\n    for _ in 1:(sweeps_record * length(sys.spins) / pmuca.size); spin_flip!(sys, alg); end\n    merge_histograms!(pmuca, alg.ensemble.histogram)\n    if is_root(pmuca)\n        update!(ensemble(alg); mode=:simple)\n        push!(mpi_hists, deepcopy(alg.ensemble.histogram))\n        push!(mpi_lws,   deepcopy(alg.ensemble.logweight))\n    end\n    distribute_logweight!(pmuca, alg.ensemble.logweight)\nend\n\nif is_root(pmuca)\n    plt, rmse = plot_muca(mpi_hists, mpi_lws; title=\"MPI\")\n    println(\"MPI RMSE = \", round(last(rmse), digits=4))\n    plt\nend","category":"section"},{"location":"generated/muca_Ising2D/#Production-runs","page":"Multicanonical sampling: Ising 2D","title":"Production runs","text":"For true parallelism, run the standalone MPI script in the same folder:\n\nmpiexec -n 4 julia --project=docs \\\n    docs/src/examples/spin_systems/muca_Ising2D_mpi.jl\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"generated/muca_sum_gaussian/#Large-Deviation-Theory:-Sum-of-Gaussian-Random-Variables","page":"Multicanonical: Sum of Gaussians","title":"Large Deviation Theory: Sum of Gaussian Random Variables","text":"Large deviation theory (LDT) describes the probability of observing rare, atypical fluctuations of macroscopic observables far from their mean. For a sum S_N = sum_i=1^N X_i of i.i.d. random variables, the central limit theorem governs typical fluctuations, but LDT governs the exponentially rare tails.\n\nThis example uses the sum of N Gaussian random variables as a tractable benchmark — the exact distribution is known analytically — and demonstrates three sampling strategies:\n\nDirect sampling — reference\nImportance sampling via Metropolis with a biasing field beta\nMulticanonical sampling — flat histogram across the full distribution\n\nusing Random, Distributions\nusing StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots, ProgressMeter","category":"section"},{"location":"generated/muca_sum_gaussian/#CI-parameters","page":"Multicanonical: Sum of Gaussians","title":"CI parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_direct   = CI_MODE ? 1_000   : 100_000\nn_therm    = CI_MODE ? 100     : 10_000\nn_metro    = CI_MODE ? 1_000   : 1_000_000\nn_muca     = CI_MODE ? 1_000   : 10_000_000\nn_muca_known = CI_MODE ? 1_000 : 50_000_000\nn_iter     = CI_MODE ? 3       : 10\nn_iter_steps = CI_MODE ? 1_000 : 5_000_000","category":"section"},{"location":"generated/muca_sum_gaussian/#Parameters","page":"Multicanonical: Sum of Gaussians","title":"Parameters","text":"μ, σ, N = 0.0, 1.0, 100\n\n# exact distribution of S_N is Normal(N*μ, sqrt(N)*σ)\npdf_sum     = Normal(N*μ, sqrt(N)*σ)\nstd_sum     = sqrt(N)*σ\nbins_sum    = (N*μ - 10*std_sum) : (std_sum/10) : (N*μ + 10*std_sum)\ncenters_sum = collect(bins_sum[1:end-1] .+ diff(collect(bins_sum))./2)\nlogpdf_sum  = logpdf.(pdf_sum, centers_sum)","category":"section"},{"location":"generated/muca_sum_gaussian/#System-definition","page":"Multicanonical: Sum of Gaussians","title":"System definition","text":"The system state is a vector of N Gaussian random variables together with their running sum. Only the sum enters the sampling weight; the individual variables evolve under their own Gaussian prior via a Metropolis-within-Gibbs step.\n\nmutable struct SumGaussianRVs\n    logpdf_rv :: Function\n    rvs       :: Vector{Float64}\n    sum_rvs   :: Float64\n    function SumGaussianRVs(rng, N; μ=0.0, σ=1.0)\n        dist = Normal(μ, σ)\n        rvs  = rand(rng, dist, N)\n        new(x -> logpdf(dist, x), rvs, sum(rvs))\n    end\nend\n\nsum_rvs(sys::SumGaussianRVs) = sys.sum_rvs\n\nEach update proposes a move for one randomly chosen variable. The proposal is first filtered by the Gaussian prior (Metropolis-within-Gibbs), then accepted by the sampling algorithm based on the sum.\n\nfunction update!(sys::SumGaussianRVs, alg::AbstractImportanceSampling; δ=0.5)\n    idx    = rand(alg.rng, 1:length(sys.rvs))\n    rv_old = sys.rvs[idx]\n    rv_new = rv_old + δ * (2*rand(alg.rng) - 1)\n    if rand(alg.rng) < exp(sys.logpdf_rv(rv_new) - sys.logpdf_rv(rv_old))\n        sum_new = sys.sum_rvs + (rv_new - rv_old)\n        if accept!(alg, sum_new, sys.sum_rvs)\n            sys.sum_rvs  = sum_new\n            sys.rvs[idx] = rv_new\n        end\n    else\n        alg.steps += 1\n    end\nend","category":"section"},{"location":"generated/muca_sum_gaussian/#Direct-sampling","page":"Multicanonical: Sum of Gaussians","title":"Direct sampling","text":"We draw independent sums as a reference distribution.\n\ndirect_samples = [sum(μ .+ σ .* randn(MersenneTwister(i), N)) for i in 1:n_direct]\nhist_direct    = normalize(fit(Histogram, direct_samples, bins_sum); mode=:pdf)\n\nplot(hist_direct; st=:bar, linewidth=0, alpha=0.6,\n     label=\"Direct samples\", xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Direct sampling vs exact\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum);\n      lw=2, color=:black, ls=:dash, label=\"Exact\")","category":"section"},{"location":"generated/muca_sum_gaussian/#Importance-sampling-with-Metropolis","page":"Multicanonical: Sum of Gaussians","title":"Importance sampling with Metropolis","text":"A biasing field beta tilts the sampling distribution toward larger (beta  0) or smaller (beta  0) values of S_N. At beta = 0 this reduces to uniform sampling of the Gaussian.\n\nfunction run_metropolis(; β=0.0)\n    sys  = SumGaussianRVs(MersenneTwister(23), N; μ=μ, σ=σ)\n    alg  = Metropolis(MersenneTwister(42); β=β)\n    meas = Measurements([:sum => sum_rvs => fit(Histogram, [], bins_sum)], interval=1)\n    for _ in 1:n_therm;  update!(sys, alg); end\n    for i in 1:n_metro;  update!(sys, alg); measure!(meas, sys, i); end\n    println(\"β = $(β):  acceptance = \", round(acceptance_rate(alg); digits=3))\n    return meas\nend\n\nβs      = [-0.5, 0.0, 0.5]\nresults = Dict(β => run_metropolis(β=β) for β in βs)\n\np_is = plot(centers_sum, pdf.(pdf_sum, centers_sum);\n            lw=2, color=:black, ls=:dash, label=\"Exact\",\n            xlabel=\"S_N\", ylabel=\"Density\",\n            title=\"Importance sampling\", size=(600, 250), margin=5Plots.mm)\nfor β in βs\n    w    = results[β][:sum].data.weights\n    norm = sum(w) * step(bins_sum)\n    plot!(p_is, centers_sum, w ./ norm; lw=2, label=\"β = $β\")\nend\np_is","category":"section"},{"location":"generated/muca_sum_gaussian/#Multicanonical-sampling-—-flat-histogram","page":"Multicanonical: Sum of Gaussians","title":"Multicanonical sampling — flat histogram","text":"With flat weights (w = 1) the multicanonical algorithm samples the full distribution uniformly, including the exponentially rare tails. This is equivalent to beta = 0 importance sampling but achieved without knowing the target distribution in advance.\n\nsys_muca0 = SumGaussianRVs(MersenneTwister(23), N; μ=μ, σ=σ)\nalg_muca0 = Multicanonical(MersenneTwister(100), bins_sum; init=0.0)\n\nfor _ in 1:n_therm;  update!(sys_muca0, alg_muca0); end\nreset!(alg_muca0)\nfor _ in 1:n_muca;   update!(sys_muca0, alg_muca0); end\nprintln(\"MUCA (flat):  acceptance = \", round(acceptance_rate(alg_muca0); digits=3))\n\nhist_muca0 = alg_muca0.ensemble.histogram.values\ndist_muca0 = hist_muca0 / sum(hist_muca0) / step(bins_sum)\nplot(centers_sum, dist_muca0; lw=2, label=\"MUCA (flat weights)\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Multicanonical flat histogram\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum); lw=2, color=:black, ls=:dash, label=\"Exact\")","category":"section"},{"location":"generated/muca_sum_gaussian/#Multicanonical-with-known-weights","page":"Multicanonical: Sum of Gaussians","title":"Multicanonical with known weights","text":"If the target distribution is known, we can initialise the weights to the exact log-PDF and add linear tails to prevent the chain running away at the boundaries.\n\nsys_known = SumGaussianRVs(MersenneTwister(42), N; μ=μ, σ=σ)\nalg_known = Multicanonical(MersenneTwister(42), bins_sum)\nlw        = logweight(alg_known)\ncs        = get_centers(lw)\n\nset!(lw, (first(cs), last(cs)), x -> -logpdf(pdf_sum, x))\n\nx_left  = -3*std_sum\nx_right = +3*std_sum\nset!(lw, (first(cs), x_left),  x -> lw(x_left)  + (x - x_left)  * 2.0)\nset!(lw, (x_right,  last(cs)), x -> lw(x_right) - (x - x_right) * 2.0)\n\nplot(cs, get_values(lw); lw=2, label=\"Initialised logweight\",\n     xlabel=\"S_N\", ylabel=\"log w(S_N)\",\n     title=\"Logweight vs exact log-PDF\", size=(600, 250), margin=5Plots.mm)\nplot!(cs, -logpdf_sum; lw=2, color=:black, ls=:dash, label=\"Exact −log PDF\")\n\nfor _ in 1:n_therm;      update!(sys_known, alg_known; δ=0.1); end\nreset!(alg_known)\nfor _ in 1:n_muca_known; update!(sys_known, alg_known; δ=0.1); end\nprintln(\"MUCA (known): acceptance = \", round(acceptance_rate(alg_known); digits=3))\n\nhist_known = alg_known.ensemble.histogram.values\ndist_known = hist_known / sum(hist_known) / step(bins_sum)\nplot(centers_sum, dist_known; lw=2, label=\"MUCA (known weights)\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"MUCA with exact initialisation\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum); lw=2, color=:black, ls=:dash, label=\"Exact\")","category":"section"},{"location":"generated/muca_sum_gaussian/#Multicanonical-iteration","page":"Multicanonical: Sum of Gaussians","title":"Multicanonical iteration","text":"Starting from flat weights, the algorithm iteratively refines the log-weights until the histogram is flat across the full support. Linear boundary tails are reapplied after each iteration to prevent the chain escaping the binned region.\n\nsys_iter = SumGaussianRVs(MersenneTwister(42), N; μ=μ, σ=σ)\nalg_iter = Multicanonical(MersenneTwister(42), bins_sum)\n\niter_hists  = BinnedObject[]\niter_lws    = BinnedObject[]\niter_accept = Float64[]\n\nlw_iter  = logweight(alg_iter)\ncs_iter  = get_centers(lw_iter)\nx_left   = first(bins_sum) + std_sum\nx_right  = last(bins_sum)  - std_sum\ni_left   = searchsortedfirst(cs_iter, x_left)\ni_right  = searchsortedlast(cs_iter,  x_right)\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:n_iter\n    for _ in 1:n_therm;      update!(sys_iter, alg_iter); end\n    reset!(alg_iter)\n    for _ in 1:n_iter_steps; update!(sys_iter, alg_iter); end\n\n    MonteCarloX.update!(ensemble(alg_iter); mode=:simple)\n\n    wl = get_values(lw_iter)[i_left]\n    wr = get_values(lw_iter)[i_right]\n    set!(lw_iter, (first(cs_iter), cs_iter[i_left]),  x -> wl + (x - cs_iter[i_left]) * 2.0)\n    set!(lw_iter, (cs_iter[i_right], last(cs_iter)),  x -> wr - (x - cs_iter[i_right]) * 2.0)\n\n    push!(iter_hists,  deepcopy(ensemble(alg_iter).histogram))\n    push!(iter_lws,    deepcopy(ensemble(alg_iter).logweight))\n    push!(iter_accept, acceptance_rate(alg_iter))\nend\n\nplot(iter_accept; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     title=\"Convergence of acceptance rate\", label=nothing,\n     size=(600, 220), margin=5Plots.mm)\n\nEach panel shows the evolution of the histogram (left) and the estimated log-DOS against the exact reference (right) over iterations.\n\nfunction plot_muca_convergence(hists, lws; ref_logpdf=logpdf_sum)\n    n    = length(hists)\n    cols = palette(:viridis, max(n,2))[1:n]\n    xs   = get_centers(hists[1].bins[1])\n    i0   = searchsortedlast(xs, 0.0)\n\n    p1 = plot(xlabel=\"S_N\", ylabel=\"Counts\", title=\"Histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, xs, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=\"S_N\", ylabel=\"-log w\", title=\"Log-DOS vs exact\", legend=:topright)\n    for i in 1:n\n        w = -lws[i].values .+ lws[i].values[i0]\n        plot!(p2, xs, w; lw=2, color=cols[i], label=\"\")\n    end\n    plot!(p2, xs, ref_logpdf .- ref_logpdf[i0];\n          lw=2, color=:black, ls=:dash, label=\"Exact\")\n\n    return plot(p1, p2; layout=(1,2), size=(900, 280), margin=4Plots.mm)\nend\n\nplot_muca_convergence(iter_hists, iter_lws)","category":"section"},{"location":"generated/muca_sum_gaussian/#Reweighting-to-a-biased-ensemble","page":"Multicanonical: Sum of Gaussians","title":"Reweighting to a biased ensemble","text":"A single multicanonical run can be reweighted post-hoc to any target ensemble with biasing field beta, recovering the same result as a dedicated Metropolis run at that beta.\n\nβ_rw    = 0.5\nhist_rw = deepcopy(ensemble(alg_iter).histogram)\nfor i in eachindex(hist_rw.values)\n    c = hist_rw.bins[1].centers[i]\n    hist_rw.values[i] *= exp(-β_rw * c - iter_lws[end].values[i])\nend\nnorm_rw = sum(hist_rw.values) * step(bins_sum)\n\nw_metro = results[β_rw][:sum].data.weights\nnorm_m  = sum(w_metro) * step(bins_sum)\n\nplot(centers_sum, hist_rw.values ./ norm_rw;\n     lw=2, color=:black, label=\"MUCA reweighted β=$β_rw\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Reweighting vs direct Metropolis\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, w_metro ./ norm_m;\n      lw=2, color=:steelblue, ls=:dash, label=\"Metropolis β=$β_rw\")\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"weights/#Weights","page":"Weights","title":"Weights","text":"Weights determine relative probabilities in equilibrium workflows. Algorithms only need differences in log weight, so the representation can stay flexible.\n\nThe same callable concept also covers Bayesian targets:\n\nBayesian inference: logweight(theta) = logposterior(theta) = loglikelihood(theta) + logprior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nIn the sampler API this callable is stored as the algorithm ensemble, with logweight(alg) as an equivalent accessor.\n\nFor canonical targets,\n\npi(x) = frace^-beta E(x)Z(beta)\n\nso\n\nlog pi(x) = -beta E(x) - log Z(beta)\n\nand local acceptance decisions depend on\n\nDelta log pi = -betaDelta E","category":"section"},{"location":"weights/#1)-Canonical-ensemble:-BoltzmannEnsemble","page":"Weights","title":"1) Canonical ensemble: BoltzmannEnsemble","text":"For energy E, the log weight is -beta E.\n\nusing Random\nusing MonteCarloX\n\nrng = MersenneTwister(1)\nalg = Metropolis(rng; β=0.5)  # internally uses BoltzmannEnsemble(0.5)\n\nUse this for standard fixed-temperature sampling.","category":"section"},{"location":"weights/#2)-Tabulated-weights:-BinnedObject","page":"Weights","title":"2) Tabulated weights: BinnedObject","text":"Use when the weight is not known analytically, or when adapting it online (multicanonical or Wang-Landau).\n\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nlw[0]   = 1.5\nvalue   = lw(0)\nlw_zero = zero(lw)\n\nBinnedObject supports discrete and continuous bin definitions, including multidimensional bin tuples.","category":"section"},{"location":"weights/#How-to-choose","page":"Weights","title":"How to choose","text":"Known canonical target: BoltzmannEnsemble\nExploratory generalized-ensemble run: BinnedObject + Multicanonical or WangLandau","category":"section"},{"location":"weights/#API-reference","page":"Weights","title":"API reference","text":"","category":"section"},{"location":"weights/#MonteCarloX.BoltzmannEnsemble","page":"Weights","title":"MonteCarloX.BoltzmannEnsemble","text":"BoltzmannEnsemble\n\nCanonical-ensemble score with logweight(E) = -beta * E.\n\n\n\n\n\n","category":"type"},{"location":"weights/#MonteCarloX.FunctionEnsemble","page":"Weights","title":"MonteCarloX.FunctionEnsemble","text":"FunctionEnsemble\n\nWrap an arbitrary callable (e.g. Bayesian logdensity/logposterior function) in an ensemble object.\n\n\n\n\n\n","category":"type"},{"location":"weights/#MonteCarloX.BinnedObject","page":"Weights","title":"MonteCarloX.BinnedObject","text":"BinnedObject(domain::AbstractRange, init)\n\nConstruct a binned log weight object for the given domain and initial value. The type of domain determines the specific binned log weight type:\n\nExamples\n\n# Discrete 1D\nbo1d = BinnedObject(0:10, 0.0)\n# Discrete ND\nbo2d = BinnedObject((0:5, 0:5), 0.0)\n# Continuous 1D\nbo1d_cont = BinnedObject(0.0:0.5:5.0, 0.0)\n# Continuous ND\nbo2d_cont = BinnedObject((0.0:0.5:5.0, 0.0:0.5:5.0), 0.0)\n\n\n\n\n\n","category":"type"},{"location":"weights/#MonteCarloX.get_centers","page":"Weights","title":"MonteCarloX.get_centers","text":"get_centers(bo::BinnedObject, dim::Int=1)\n\nReturn bin centers along dimension dim. For discrete bins this returns the bin support values.\n\n\n\n\n\n","category":"function"},{"location":"weights/#MonteCarloX.get_values-Tuple{BinnedObject}","page":"Weights","title":"MonteCarloX.get_values","text":"get_values(bo::BinnedObject)\n\nReturn the underlying array of bin values.\n\n\n\n\n\n","category":"method"},{"location":"weights/#Base.zero-Tuple{BinnedObject}","page":"Weights","title":"Base.zero","text":"zero(lw::BinnedObject)\n\nReturn a new BinnedObject of the same bins as lw but with all values set to zero.\n\n\n\n\n\n","category":"method"},{"location":"generated/gillespie_dimerization/#Reversible-Dimerization-with-Gillespie-Algorithm","page":"Gillespie: Dimerization Reaction","title":"Reversible Dimerization with Gillespie Algorithm","text":"This example demonstrates continuous-time stochastic simulation of a reversible dimerization reaction using the Gillespie algorithm:\n\nA + B undersetk_textoffstackrelk_textonrightleftharpoons AB\n\nThe Gillespie algorithm samples exact trajectories of the chemical master equation by drawing the time to the next reaction event from an exponential distribution and selecting the reaction channel proportionally to its rate.\n\nusing Random, StatsBase, Plots\nusing MonteCarloX","category":"section"},{"location":"generated/gillespie_dimerization/#System-definition","page":"Gillespie: Dimerization Reaction","title":"System definition","text":"The system state tracks molecule counts of three species. Two reaction channels are defined: association (A + B → AB) and dissociation (AB → A + B).\n\nmutable struct ReversibleDimerModel <: AbstractSystem\n    A    :: Int\n    B    :: Int\n    AB   :: Int\n    k_on  :: Float64\n    k_off :: Float64\nend\n\n# propensities: rates at which each reaction fires\nreaction_rates(sys::ReversibleDimerModel, t) = [\n    sys.k_on  * sys.A * sys.B,   ## association\n    sys.k_off * sys.AB,           ## dissociation\n]\n\nfunction modify!(sys::ReversibleDimerModel, event::Int, t)\n    if event == 1 && sys.A > 0 && sys.B > 0\n        sys.A -= 1;  sys.B -= 1;  sys.AB += 1\n    elseif event == 2 && sys.AB > 0\n        sys.A += 1;  sys.B += 1;  sys.AB -= 1\n    end\n    return sys\nend","category":"section"},{"location":"generated/gillespie_dimerization/#Parameters-and-initialisation","page":"Gillespie: Dimerization Reaction","title":"Parameters and initialisation","text":"We start with 30 molecules each of A and B and no dimers. The on-rate k_texton = 001 and off-rate k_textoff = 05 set the equilibrium dimer fraction.\n\nsys = ReversibleDimerModel(30, 20, 0, 0.01, 0.5)\nalg = Gillespie(MersenneTwister(23))\nT   = 200.0\n\nprintln(\"Initial state: A=$(sys.A),  B=$(sys.B),  AB=$(sys.AB)\")\nprintln(\"k_on = $(sys.k_on),  k_off = $(sys.k_off)\")","category":"section"},{"location":"generated/gillespie_dimerization/#Simulation","page":"Gillespie: Dimerization Reaction","title":"Simulation","text":"step! draws the next event time from the Gillespie distribution and returns the event index. Measurements are recorded before modify! so that each sample reflects the state during the inter-event interval.\n\nmeasurement_times = collect(0.0:0.5:T)\nmeasurements = Measurements([\n    :A  => (s -> s.A)  => Int[],\n    :B  => (s -> s.B)  => Int[],\n    :AB => (s -> s.AB) => Int[],\n], measurement_times)\n\nmeasure!(measurements, sys, alg.time)   ## record initial state\n\nwhile alg.time <= T\n    t_new, event = step!(alg, t -> reaction_rates(sys, t))\n    measure!(measurements, sys, t_new)  ## before modify!\n    modify!(sys, event, t_new)\nend\n\nprintln(\"Final time   : \", round(alg.time; digits=2))\nprintln(\"Final state  : A=$(sys.A),  B=$(sys.B),  AB=$(sys.AB)\")\nprintln(\"Total events : \", alg.steps)","category":"section"},{"location":"generated/gillespie_dimerization/#Trajectory","page":"Gillespie: Dimerization Reaction","title":"Trajectory","text":"The system reaches a dynamic equilibrium in which molecules continuously associate and dissociate. The sum A + B + 2·AB is conserved throughout.\n\nA_t  = measurements[:A].data\nB_t  = measurements[:B].data\nAB_t = measurements[:AB].data\n\nplot(measurement_times, A_t;  lw=2, label=\"A\",\n     xlabel=\"Time\", ylabel=\"Count\",\n     title=\"Reversible dimerization trajectory\",\n     size=(700, 280), margin=5Plots.mm)\nplot!(measurement_times, B_t;  lw=2, label=\"B\")\nplot!(measurement_times, AB_t; lw=2, label=\"AB\")","category":"section"},{"location":"generated/gillespie_dimerization/#Equilibrium-statistics","page":"Gillespie: Dimerization Reaction","title":"Equilibrium statistics","text":"Time-averaged counts after the system has equilibrated. The law of mass action predicts langle AB rangle  (langle Aranglelangle Brangle) = k_textonk_textoff.\n\nt_eq  = T / 4   ## discard first quarter as transient\ni_eq  = searchsortedfirst(measurement_times, t_eq)\n\nA_eq  = mean(A_t[i_eq:end])\nB_eq  = mean(B_t[i_eq:end])\nAB_eq = mean(AB_t[i_eq:end])\n\nratio_sim   = AB_eq / (A_eq * B_eq)\nratio_exact = sys.k_on / sys.k_off\n\nprintln(\"Time-averaged counts (t > $(t_eq)):\")\nprintln(\"  ⟨A⟩  = \", round(A_eq;  digits=3))\nprintln(\"  ⟨B⟩  = \", round(B_eq;  digits=3))\nprintln(\"  ⟨AB⟩ = \", round(AB_eq; digits=3))\nprintln(\"Mass-action ratio — simulation: \", round(ratio_sim;   digits=4),\n                          \"  exact: \",      round(ratio_exact; digits=4))\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"generated/importance_Ising2D/#Importance-Sampling-of-the-2D-Ising-Model","page":"Importance sampling: Ising Model","title":"Importance Sampling of the 2D Ising Model","text":"This example demonstrates importance sampling for the 2D Ising model with Hamiltonian H = -Jsum_langle ijrangle s_i s_j. We cover three topics: (1) system implementations and their runtime, (2) sampling algorithms, and (3) validation against the exact solution.\n\nusing Random, StatsBase, Plots, BenchmarkTools\nusing MonteCarloX, SpinSystems\nusing Graphs, SparseArrays","category":"section"},{"location":"generated/importance_Ising2D/#CI-parameters","page":"Importance sampling: Ising Model","title":"CI parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\ntherm_sweeps     = CI_MODE ? 10    : 1_000\nprod_sweeps      = CI_MODE ? 100   : 10_000\nmeasure_interval = 10","category":"section"},{"location":"generated/importance_Ising2D/#Parameters","page":"Importance sampling: Ising Model","title":"Parameters","text":"L    = 8\nβ    = 0.3\nseed = 42","category":"section"},{"location":"generated/importance_Ising2D/#System-implementations","page":"Importance sampling: Ising Model","title":"System implementations","text":"MonteCarloX.jl provides several ways to represent the 2D Ising model, trading generality for performance:\n\nIsing([L,L]): general lattice, uses Graphs.jl under the hood\nIsing(J_matrix): general, accepts any sparse coupling matrix\nIsingLatticeOptim: hard-coded 2D square lattice with periodic boundaries\n\nWe benchmark a single spin_flip! step for each.\n\nalg_bench = Metropolis(Xoshiro(seed); β=β)\n\nsys_graph  = Ising([L, L]; J=1, periodic=true)\ninit!(sys_graph,  :random, rng=MersenneTwister(seed))\n\ngrid_graph = Graphs.SimpleGraphs.grid([L, L]; periodic=true)\nsys_matrix = Ising(SparseMatrixCSC{Float64,Int}(adjacency_matrix(grid_graph)))\ninit!(sys_matrix, :random, rng=MersenneTwister(seed))\n\nsys_optim  = IsingLatticeOptim(L, L)\ninit!(sys_optim,  :random, rng=MersenneTwister(seed))\n\nprintln(\"Graph-based Ising:\")\n@btime spin_flip!($sys_graph,  $alg_bench)\nprintln(\"Matrix-coupling Ising:\")\n@btime spin_flip!($sys_matrix, $alg_bench)\nprintln(\"Optimized 2D Ising:\")\n@btime spin_flip!($sys_optim,  $alg_bench)\n\nThe optimized implementation is significantly faster because it exploits the fixed lattice geometry to avoid graph traversal and sparse matrix lookups. The graph-based version is the most flexible — it works for any lattice geometry or connectivity without any code changes.","category":"section"},{"location":"generated/importance_Ising2D/#Custom-acceptance-rule","page":"Importance sampling: Ising Model","title":"Custom acceptance rule","text":"For the 2D Ising model Delta E in -8-4048, so we can precompute the two non-trivial acceptance probabilities and avoid calling exp at every step. This shows how to extend MonteCarloX.jl with a custom algorithm by implementing the accept! interface.\n\nmutable struct TableMetropolis{R<:AbstractRNG} <: AbstractMetropolis\n    rng      :: R\n    p4       :: Float64\n    p8       :: Float64\n    steps    :: Int\n    accepted :: Int\nend\n\nTableMetropolis(rng::AbstractRNG; β::Real) =\n    TableMetropolis(rng, exp(-4β), exp(-8β), 0, 0)\n\n@inline function MonteCarloX.accept!(alg::TableMetropolis, dE::Int)\n    alg.steps += 1\n    dE <= 0 && (alg.accepted += 1; return true)\n    p        = dE == 4 ? alg.p4 : alg.p8\n    accepted = rand(alg.rng) < p\n    alg.accepted += accepted\n    return accepted\nend\n\nsys_table = IsingLatticeOptim(L, L)\ninit!(sys_table, :random, rng=Xoshiro(seed))\nalg_table = TableMetropolis(Xoshiro(seed); β=β)\n\nprintln(\"Standard Metropolis + Xoshiro:\")\n@btime spin_flip!($sys_optim, $alg_bench)\nprintln(\"TableMetropolis + Xoshiro:\")\n@btime spin_flip!($sys_table, $alg_table)","category":"section"},{"location":"generated/importance_Ising2D/#Simulation-helper","page":"Importance sampling: Ising Model","title":"Simulation helper","text":"function run_chain!(sys, alg)\n    N = length(sys.spins)\n    measurements = Measurements([\n        :energy        => energy        => Float64[],\n        :magnetization => magnetization => Float64[],\n    ], interval=measure_interval)\n    for _ in 1:(N * therm_sweeps); spin_flip!(sys, alg); end\n    hasmethod(reset!, Tuple{typeof(alg)}) && reset!(alg)\n    for i in 1:(N * prod_sweeps)\n        spin_flip!(sys, alg)\n        measure!(measurements, sys, i)\n    end\n    energies = measurements[:energy].data\n    mags     = measurements[:magnetization].data\n    return (; energies, mags,\n              avg_E = mean(energies) / N,\n              avg_M = mean(abs.(mags)) / N)\nend","category":"section"},{"location":"generated/importance_Ising2D/#Validation-helper","page":"Importance sampling: Ising Model","title":"Validation helper","text":"The exact energy distribution follows the Boltzmann weights applied to the exact density of states (Beale 1996). plot_importance_sampling overlays the sampled histograms of all algorithms against this reference.\n\nexact_logdos          = logdos_exact_ising2D(L)\nexact_logdos.values .-= exact_logdos[0]\nlog_dos  = exact_logdos.values\nlog_w    = log_dos .- β .* get_centers(exact_logdos)\nlog_Z    = reduce((a,b) -> a > b ? a + log1p(exp(b-a)) : b + log1p(exp(a-b)),\n                  filter(isfinite, log_w))\nmask     = isfinite.(log_dos)\nE_exact  = get_centers(exact_logdos)\nP_exact  = zeros(length(log_w))\nP_exact[mask] = exp.(log_w[mask] .- log_Z)\n\nfunction plot_importance_sampling(results, labels)\n    p_ts   = plot(xlabel=\"Measurement step\", ylabel=\"Energy\",\n                  title=\"Time series\", legend=:topright)\n    p_dist = plot(xlabel=\"Energy\", ylabel=\"Probability\",\n                  title=\"Distribution vs exact\", legend=:topright)\n    cols = palette(:tab10)\n    for (i, (res, label)) in enumerate(zip(results, labels))\n        plot!(p_ts, res.energies; lw=1, color=cols[i])\n        edges = get_edges(exact_logdos.bins[1])\n        hist  = fit(Histogram, res.energies, edges, closed=:left)\n        dist  = StatsBase.normalize(hist; mode=:probability)\n        plot!(p_dist, dist; label=label, lw=2, color=cols[i])\n    end\n    mask = isfinite.(P_exact)\n    plot!(p_dist, E_exact[mask], P_exact[mask];\n          label=\"Exact\", color=:black, lw=2, ls=:dash)\n    return plot(p_ts, p_dist; layout=(1,2), size=(980,320), margin=4Plots.mm)\nend","category":"section"},{"location":"generated/importance_Ising2D/#Metropolis","page":"Importance sampling: Ising Model","title":"Metropolis","text":"The Metropolis-Hastings algorithm accepts a proposed spin flip with probability min(1 e^-betaDelta E). It is the standard workhorse for spin systems: simple, general, and efficient.\n\nsys_meta = IsingLatticeOptim(L, L)\ninit!(sys_meta, :random, rng=MersenneTwister(seed))\nres_meta = run_chain!(sys_meta, Metropolis(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_meta], [\"Metropolis\"])","category":"section"},{"location":"generated/importance_Ising2D/#Heat-Bath","page":"Importance sampling: Ising Model","title":"Heat Bath","text":"The Heat Bath algorithm accepts with probability 1(1+e^betaDelta E), which corresponds to directly sampling the conditional distribution of a single spin given its neighbours. It tends to have shorter autocorrelation times than Metropolis at low temperatures.\n\nsys_hb = IsingLatticeOptim(L, L)\ninit!(sys_hb, :random, rng=MersenneTwister(seed))\nres_hb = run_chain!(sys_hb, HeatBath(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_hb], [\"HeatBath\"])","category":"section"},{"location":"generated/importance_Ising2D/#Glauber","page":"Importance sampling: Ising Model","title":"Glauber","text":"The Glauber dynamics use the same acceptance probability as Heat Bath and are equivalent for spin-12 systems. The distinction matters for systems with more than two spin states, where Glauber uses a linearised transition rate rather than the exact conditional distribution.\n\nsys_gla = IsingLatticeOptim(L, L)\ninit!(sys_gla, :random, rng=MersenneTwister(seed))\nres_gla = run_chain!(sys_gla, Glauber(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_gla], [\"Glauber\"])","category":"section"},{"location":"generated/importance_Ising2D/#Comparison","page":"Importance sampling: Ising Model","title":"Comparison","text":"All three algorithms sample the same Boltzmann distribution. Overlaying them confirms that the choice of algorithm does not affect the physics, only the efficiency.\n\nplot_importance_sampling(\n    [res_meta, res_hb, res_gla],\n    [\"Metropolis\", \"HeatBath\", \"Glauber\"]\n)\n\nprintln(\"Average energy per spin:\")\nprintln(\"  Exact      : \", round(mean(get_centers(exact_logdos) .* P_exact); digits=3))\nprintln(\"  Metropolis : \", round(res_meta.avg_E; digits=3))\nprintln(\"  HeatBath   : \", round(res_hb.avg_E;   digits=3))\nprintln(\"  Glauber    : \", round(res_gla.avg_E;   digits=3))\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"helper/#Helper-Utilities","page":"Helper","title":"Helper Utilities","text":"This page groups lower-level tools used by algorithms and model packages.","category":"section"},{"location":"helper/#Numeric-helpers","page":"Helper","title":"Numeric helpers","text":"log_sum: numerically stable log-sum operations\nbinary_search: utility for sorted-domain lookups\nlogistic: logistic helper used in acceptance rules\nkldivergence: histogram/function divergence helper","category":"section"},{"location":"helper/#RNG-helper","page":"Helper","title":"RNG helper","text":"MutableRandomNumbers is a lightweight utility for deterministic random-number replay and control in workflows that need mutable RNG-like streams.","category":"section"},{"location":"helper/#Event-handler-backends","page":"Helper","title":"Event-handler backends","text":"These structures back event selection and queue-based scheduling in continuous-time samplers.","category":"section"},{"location":"helper/#MonteCarloX.log_sum","page":"Helper","title":"MonteCarloX.log_sum","text":"log_sum(a::T,b::T)\n\nReturn result of logarithmic sum c = ln(A+B) = a + ln(1+e^b-a) where C = e^c = A+B = e^a + e^b.\n\nThis is useful for sums that involve elements that span multiple orders of magnitude, e.g., the partition sum that is required as normalization factor during reweighting.\n\nExamples\n\njulia> exp(MonteCarloX.log_sum(log(2.), log(3.)))\n5.000000000000001\n\n\n\n\n\n\n","category":"function"},{"location":"helper/#MonteCarloX.binary_search","page":"Helper","title":"MonteCarloX.binary_search","text":"binary_search(sorted::AbstractVector{T}, value::T)::Int where {T<:Real}\n\nPerform a binary search to return the index i of an sorted array such that sorted[i-1] < value <= sorted[i]\n\nExamples\n\njulia> MonteCarloX.binary_search([1.,2.,3.,4.],2.5)\n3\n\njulia> MonteCarloX.binary_search([1,2,3,4],2)\n2\n\n\n\n\n\n","category":"function"},{"location":"helper/#MonteCarloX.logistic","page":"Helper","title":"MonteCarloX.logistic","text":"logistic(x::Real)\n\nNumerically stable logistic sigmoid:\n\nσ(x) = 1 / (1 + exp(-x))\n\n\n\n\n\n","category":"function"},{"location":"helper/#StatsBase.kldivergence","page":"Helper","title":"StatsBase.kldivergence","text":"kldivergence(P::Histogram, Q::Function)\n\nKullback-Leibler divergence between an empirical distribution (measured) and a reference distribution (analytic)\n\nSo far this is defined only for 1-dimensional distributions of type StatsBase.Histogram\n\n\n\n\n\n","category":"function"},{"location":"helper/#MonteCarloX.MutableRandomNumbers","page":"Helper","title":"MonteCarloX.MutableRandomNumbers","text":"MutableRandomNumbers([rng_base=GLOBAL_RNG], size, mode:=static)\n\nCreate a MutableRandomNumbers RNG object with a vector of size size containing floating-point randomnumbers initially generated with `rngbase`. Random numbers are then generated sequentially from this vector. The RNG object can be initialized in two modes:\n\n:static - then there is an exception thrown once all random numbers are used\n:dynamic - then there are new random numbers generated on the flow from the (copied) rng\n\nExamples\n\njulia> rng = MutableRandomNumbers(MersenneTwister(1234),100);\n\njulia> x1 = rand(rng, 2)\n2-element Array{Float64,1}:\n 0.5908446386657102\n 0.7667970365022592\n\njulia> rng = MersenneTwister(1234);\n\njulia> x2 = rand(rng, 2)\n2-element Array{Float64,1}:\n 0.5908446386657102\n 0.7667970365022592\n\njulia> x1 == x2\ntrue\n\nImportantly, the random numbers can be accessed and manipulated as in ordinary array objects.\n\njulia> rng[1]\n0.5908446386657102\njulia> rng[3] = 0.2\njulia> rand(rng)\n0.2\n\nUse reset! in order to rerun the (manipulated) random number sequence.\n\njulia> reset!(rng)\n\n\n\n\n\n\n","category":"type"},{"location":"helper/#MonteCarloX.reset!-Tuple{MutableRandomNumbers, Int64}","page":"Helper","title":"MonteCarloX.reset!","text":"reset!(rng::MutableRandomNumbers, [index::Int=0])\n\nReset the state of a MutableRandomNumbers object rng to index. Default resets the RNG object to the pre-initial index (0)\n\n\n\n\n\n","category":"method"},{"location":"helper/#MonteCarloX.ListEventRateSimple","page":"Helper","title":"MonteCarloX.ListEventRateSimple","text":"ListEventRateSimple{T}\n\nSimplest event manager for a list of events of type T with a static list of rates.\n\nAPI implemented\n\nlength(event_handler)\ngetindex(event_handler, index)\nsetindex!(event_handler, value, index)\n\n\n\n\n\n","category":"type"},{"location":"helper/#MonteCarloX.ListEventRateActiveMask","page":"Helper","title":"MonteCarloX.ListEventRateActiveMask","text":"ListEventRateActiveMask{T}\n\nEvent manager with explicit active-mask tracking for sparse active rates.\n\n\n\n\n\n","category":"type"},{"location":"helper/#MonteCarloX.EventQueue","page":"Helper","title":"MonteCarloX.EventQueue","text":"EventQueue{T}([start_time::Float64])\n\nOrdered time-event queue storing (time, event) tuples.\n\nAPI implemented\n\nlength(event_handler)\ngetindex(event_handler, index)\npopfirst!(event_handler)\nadd!(event_handler, tuple_time_event)\nget_time(event_handler)\nset_time!(event_handler, time)\n\n\n\n\n\n","category":"type"},{"location":"continuous_time_sampling_algorithms/#Continuous-Time-Sampling-Algorithms","page":"Continuous-Time Sampling","title":"Continuous-Time Sampling Algorithms","text":"Continuous-time Monte Carlo in MonteCarloX is event-driven. You sample when the next event happens and which event happens.","category":"section"},{"location":"continuous_time_sampling_algorithms/#Why-this-differs-from-Metropolis-style-sampling","page":"Continuous-Time Sampling","title":"Why this differs from Metropolis-style sampling","text":"Importance sampling focuses on stationary distributions.\nContinuous-time sampling focuses on trajectories in real/simulation time.\n\nConceptually, trajectories can be viewed as states in path space. The continuous-time interface is a computational specialization for explicit event-time dynamics.\n\nPath-space notation:\n\ntrajectory omega = (x_t)_t in 0T\ntarget path distribution pi(omega) = p(omega mid lambda)","category":"section"},{"location":"continuous_time_sampling_algorithms/#Gillespie-workflow","page":"Continuous-Time Sampling","title":"Gillespie workflow","text":"At each step:\n\ncompute total rate\nsample waiting time mathrmdt sim mathrmExp(lambda_mathrmtot)\nsample event index proportional to rates\nadvance time and apply event update\n\nGillespie stores steps and current time.","category":"section"},{"location":"continuous_time_sampling_algorithms/#Minimal-loop","page":"Continuous-Time Sampling","title":"Minimal loop","text":"using Random\nusing MonteCarloX\n\nalg = Gillespie(MersenneTwister(10))\nrates = [0.5, 1.0]  # e.g. birth, death\nfor _ in 1:10000\n    t, event = step!(alg, rates)\n    # apply event to your state\n    # update rates from new state\nend","category":"section"},{"location":"continuous_time_sampling_algorithms/#step!-vs-advance!","page":"Continuous-Time Sampling","title":"step! vs advance!","text":"step!: one event at a time (full manual control)\nadvance!: run until total_time, with optional callbacks (measure!, update!)\n\nExample with explicit state + event source:\n\nusing Random\nusing MonteCarloX\n\nsys = Dict(:N => 30)\nevent_source(sys::Dict{Symbol,Int}) = [0.2 * sys[:N], 0.1 * sys[:N]]\nalg = Gillespie(MersenneTwister(11))\n\nmodify_cb = (state, event, t) -> begin\n    if event == 1\n        state[:N] += 1\n    elseif event == 2\n        state[:N] = max(0, state[:N] - 1)\n    end\nend\n\nadvance!(alg, sys, 20.0; modify!=modify_cb)","category":"section"},{"location":"continuous_time_sampling_algorithms/#Event-sources-supported","page":"Continuous-Time Sampling","title":"Event sources supported","text":"raw vectors of rates\nStatsBase weights\nrate-based event handlers (AbstractEventHandlerRate)\ntime-ordered event queues (AbstractEventHandlerTime)\ncallback rates_at_time(t)","category":"section"},{"location":"continuous_time_sampling_algorithms/#Low-level-building-blocks","page":"Continuous-Time Sampling","title":"Low-level building blocks","text":"next_time: waiting-time sampling (homogeneous or thinning-based)\nnext_event: event-index sampling\nnext: one combined draw (mathrmdt textevent)","category":"section"},{"location":"continuous_time_sampling_algorithms/#Example-map-(algorithm-application)","page":"Continuous-Time Sampling","title":"Example map (algorithm ↔ application)","text":"Birth-death dynamics (Gillespie): examples/stochastic_processes/gillespie_birth_death.ipynb\nReaction-network dynamics (Gillespie): examples/stochastic_processes/gillespie_dimerization.ipynb\nPoisson primitives / low-level event draws: examples/stochastic_processes/kmc_poisson.ipynb","category":"section"},{"location":"continuous_time_sampling_algorithms/#API-reference","page":"Continuous-Time Sampling","title":"API reference","text":"","category":"section"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.AbstractKineticMonteCarlo","page":"Continuous-Time Sampling","title":"MonteCarloX.AbstractKineticMonteCarlo","text":"AbstractKineticMonteCarlo <: AbstractAlgorithm\n\nBase type for continuous-time kinetic Monte Carlo algorithms.\n\n\n\n\n\n","category":"type"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.Gillespie","page":"Continuous-Time Sampling","title":"MonteCarloX.Gillespie","text":"Gillespie <: AbstractKineticMonteCarlo\n\nGillespie algorithm for continuous-time event-driven sampling.\n\nFields\n\nrng::AbstractRNG: Random number generator\nsteps::Int: Number of events sampled\ntime::Float64: Current simulation time\n\n\n\n\n\n","category":"type"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.next","page":"Continuous-Time Sampling","title":"MonteCarloX.next","text":"next(alg::AbstractKineticMonteCarlo, rates::AbstractVector)\n\nDraw next event waiting time and event id from raw rates.\n\nFor zero total rate, returns (Inf, 0).\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, rates::AbstractVector)\n\nDraw next event waiting time and event id from raw rates (StatsBase.AbstractWeights is also an AbstractVector).\n\nFor zero total rate, returns (Inf, 0).\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, event_handler::AbstractEventHandlerRate)\n\nDraw next event waiting time and event from an event handler.\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, event_handler::AbstractEventHandlerTime)\n\nDraw next event from a time-ordered event queue.\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, ratesattime::Function)\n\nDraw next event waiting time and event from a time-dependent rates function.\n\nrates_at_time is called as rates_at_time(alg.time) and should return either an AbstractVector, AbstractWeights, or AbstractEventHandlerRate.\n\n\n\n\n\n","category":"function"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.step!","page":"Continuous-Time Sampling","title":"MonteCarloX.step!","text":"step!(alg::AbstractKineticMonteCarlo, event_source)\n\nPerform one kinetic Monte Carlo step from an event_source (rates or an event handler).\n\nUpdates alg.time and alg.steps internally and returns (t_new, event).\n\nIf dt=Inf then this is reflected in the algorithm.time and returned correspondingly If event is nothing, then this is returned as well.\n\n\n\n\n\n","category":"function"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.next_time","page":"Continuous-Time Sampling","title":"MonteCarloX.next_time","text":"next_time(rng::AbstractRNG, rate_generation::Number)::Float64\n\nDraw next waiting time for a homogeneous Poisson event stream.\n\n\n\n\n\nnext_time(rng::AbstractRNG, rate::Function, rate_generation::Real)::Real\n\nDraw next waiting time for an inhomogeneous Poisson stream using thinning.\n\n\n\n\n\n","category":"function"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.next_event","page":"Continuous-Time Sampling","title":"MonteCarloX.next_event","text":"next_event(rng::AbstractRNG, rates::Union{AbstractWeights, AbstractVector})::Int\n\nDraw one event index proportional to rates.\n\n\n\n\n\n","category":"function"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.advance!","page":"Continuous-Time Sampling","title":"MonteCarloX.advance!","text":"advance!(alg::AbstractKineticMonteCarlo, sys, total_time; t0=0, measure!=measure!, modify!=modify!)\n\nAdvance system sys using alg until total_time.\n\nLoop order per step:\n\nstep!    — draw next event from event_source(sys)\nmeasure! — observe before modification: measure!(sys, event, t)\nmodify!  — apply event to state:        modify!(sys, event, t)\n\nStops early if the event source is exhausted or total time is reached.\n\n\n\n\n\n","category":"function"},{"location":"continuous_time_sampling_algorithms/#MonteCarloX.reset!-Tuple{AbstractKineticMonteCarlo}","page":"Continuous-Time Sampling","title":"MonteCarloX.reset!","text":"reset!(alg::AbstractKineticMonteCarlo)\n\nReset kinetic Monte Carlo statistics (steps, time) to zero.\n\n\n\n\n\n","category":"method"},{"location":"monte_carlo_fundamentals/#Monte-Carlo-Fundamentals","page":"Monte Carlo Fundamentals","title":"Monte Carlo Fundamentals","text":"Monte Carlo methods estimate expectations by sampling. Let X be a random variable with target density or mass function pi(x), and let f be an observable. The central quantity is\n\nmathbbE_pif(X) = int f(x)pi(x)mathrmdx\n\nwith the integral understood as a sum in discrete spaces. Given samples x_1 dots x_n distributed according to pi, Monte Carlo uses\n\nmathbbE_pif(X) approx frac1nsum_i=1^n f(x_i)","category":"section"},{"location":"monte_carlo_fundamentals/#1)-What-is-being-sampled?","page":"Monte Carlo Fundamentals","title":"1) What is being sampled?","text":"Monte Carlo workflows differ mainly in the object whose distribution you sample.\n\nState sampling: distributions over states x\nTrajectory sampling: distributions over paths omega = (x_t)_t in 0T\n\nExamples of state sampling:\n\nBayesian inference:\n\npi(theta) = p(theta mid mathcalD) propto p(mathcalD mid theta)p(theta)\n\nStatistical mechanics (microstates):\n\npi(x) = p(x mid beta) = frace^-beta E(x)Z(beta)\n\nStatistical mechanics (energy variable):\n\np(E mid beta) = fracOmega(E)e^-beta EZ(beta)\n\nwhere Omega(E) is the density of states.\n\nExamples of trajectory sampling:\n\nchemical reaction networks\nepidemic and contact processes\nkinetic spin dynamics","category":"section"},{"location":"monte_carlo_fundamentals/#2)-Unified-view:-trajectories-are-states-in-path-space","page":"Monte Carlo Fundamentals","title":"2) Unified view: trajectories are states in path space","text":"Conceptually, trajectory sampling is still state-distribution sampling, but over a higher-dimensional object space (path space).\n\nWhy keep a separate class in practice?\n\ntrajectory methods preserve explicit physical or simulation time\nevent times and event identities are sampled jointly\nAPIs are event-driven rather than proposal/reject loops\n\nSo the mathematics is unified, while computational interfaces are specialized.\n\nPath-space notation:\n\nomega: entire trajectory\npi(omega) = p(omega mid lambda): path distribution under model parameters lambda","category":"section"},{"location":"monte_carlo_fundamentals/#3)-Two-algorithmic-interfaces","page":"Monte Carlo Fundamentals","title":"3) Two algorithmic interfaces","text":"","category":"section"},{"location":"monte_carlo_fundamentals/#A.-Discrete-step-samplers-(importance-sampling-/-MCMC)","page":"Monte Carlo Fundamentals","title":"A. Discrete-step samplers (importance sampling / MCMC)","text":"Loop:\n\npropose a local change\nevaluate a log-ratio or local weight difference\naccept/reject\n\nUsed in Bayesian inference, equilibrium statistical mechanics, and many optimization/sampling hybrids.","category":"section"},{"location":"monte_carlo_fundamentals/#B.-Continuous-time-event-samplers-(kinetic-Monte-Carlo)","page":"Monte Carlo Fundamentals","title":"B. Continuous-time event samplers (kinetic Monte Carlo)","text":"Loop:\n\ncompute event rates\nsample waiting time mathrmdt\nsample event index\nadvance time and apply event\n\nUsed when timing of events is part of the model output.","category":"section"},{"location":"monte_carlo_fundamentals/#4)-Mapping-to-MonteCarloX","page":"Monte Carlo Fundamentals","title":"4) Mapping to MonteCarloX","text":"Across both interfaces, MonteCarloX keeps the same decomposition:\n\nSystem: state and model-specific updates\nWeight/rates: target density or event intensities\nAlgorithm: transition sampler\n\nMeasurements are optional and independent of the core transition logic.","category":"section"},{"location":"monte_carlo_fundamentals/#5)-Practical-simulation-recipe","page":"Monte Carlo Fundamentals","title":"5) Practical simulation recipe","text":"For most workflows, implementation follows one of two loops.","category":"section"},{"location":"monte_carlo_fundamentals/#A.-Discrete-step-sketch","page":"Monte Carlo Fundamentals","title":"A. Discrete-step sketch","text":"using Random\nusing MonteCarloX\n\nrng = MersenneTwister(1)\nlogdensity(x) = -0.5 * x^2\nalg = Metropolis(rng, logdensity)\n\nx = 0.0\nfor _ in 1:10_000\n    x_new = x + randn(alg.rng)\n    x = accept!(alg, x_new, x) ? x_new : x\nend","category":"section"},{"location":"monte_carlo_fundamentals/#B.-Continuous-time-sketch","page":"Monte Carlo Fundamentals","title":"B. Continuous-time sketch","text":"using Random\nusing MonteCarloX\n\nalg = Gillespie(MersenneTwister(2))\nrates = [0.2, 0.8]\nfor _ in 1:10_000\n    t, event = step!(alg, rates)\n    # update your state using `event`\nend","category":"section"},{"location":"monte_carlo_fundamentals/#6)-Where-to-continue","page":"Monte Carlo Fundamentals","title":"6) Where to continue","text":"For discrete-step methods and concrete examples:\nImportance Sampling Algorithms\nFor event-driven continuous-time methods and examples:\nContinuous-Time Sampling Algorithms\nThen implement your own model in Build Your Own System.","category":"section"},{"location":"generated/coin_flip/#Bayesian-Inference:-Coin-Flip-with-Importance-Sampling","page":"Coin Flip (Bayesian inference)","title":"Bayesian Inference: Coin Flip with Importance Sampling","text":"We demonstrate importance sampling via Metropolis: proposals from a random walk, acceptance based on the posterior ratio (prior × likelihood). This pattern is general and directly compatible with advanced algorithms in MonteCarloX.jl such as multicanonical and Wang-Landau sampling.\n\nusing Random, Statistics, Distributions, Plots\nusing MonteCarloX","category":"section"},{"location":"generated/coin_flip/#CI-parameters","page":"Coin Flip (Bayesian inference)","title":"CI parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_steps  = CI_MODE ? 1_000  : 100_000\nburn_in  = CI_MODE ? 200    : 10_000","category":"section"},{"location":"generated/coin_flip/#Data-and-model","page":"Coin Flip (Bayesian inference)","title":"Data and model","text":"We observe 100 coin flips with 61 heads and 39 tails. The conjugate prior is textBeta(22), giving an exact posterior textBeta(alpha + textheads beta + texttails) against which we validate the MCMC result.\n\nA key advantage of MCMC is that accept! only needs the unnormalized log-posterior — prior plus likelihood — without computing the evidence.\n\nn_heads, n_tails = 61, 39\nα_prior, β_prior = 2.0, 2.0\nprior            = Beta(α_prior, β_prior)\nposterior_exact  = Beta(α_prior + n_heads, β_prior + n_tails)\n\nlogprior(θ)      = logpdf(prior, θ)\nloglikelihood(θ) = n_heads * log(θ) + n_tails * log1p(-θ)\nlogposterior(θ)  = logprior(θ) + loglikelihood(θ)\n\nprintln(\"Data            : $(n_heads) heads, $(n_tails) tails out of $(n_heads+n_tails)\")\nprintln(\"Exact posterior : Beta($(α_prior + n_heads), $(β_prior + n_tails))\")","category":"section"},{"location":"generated/coin_flip/#Metropolis-sampling","page":"Coin Flip (Bayesian inference)","title":"Metropolis sampling","text":"A Gaussian random walk proposes new values of theta in (01). The accept! interface of MonteCarloX.jl evaluates the log-posterior ratio and handles the acceptance decision, tracking statistics automatically.\n\nfunction update!(alg::Metropolis, θ, Δ)\n    θ_new = θ + Δ * randn(alg.rng)\n    if 0.0 < θ_new < 1.0\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n    end\n    return θ\nend\n\nfunction run_metropolis(logposterior, prior; seed=2026, Δ=0.03)\n    rng     = MersenneTwister(seed)\n    alg     = Metropolis(rng, logposterior)\n    θ       = rand(rng, prior)\n    samples = Float64[]\n    for _ in 1:burn_in\n        θ = update!(alg, θ, Δ)\n    end\n    reset!(alg)\n    for _ in 1:n_steps\n        θ = update!(alg, θ, Δ)\n        push!(samples, θ)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior, prior)\n\nprintln(\"Step size Δ       : 0.03\")\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", length(samples))","category":"section"},{"location":"generated/coin_flip/#Results","page":"Coin Flip (Bayesian inference)","title":"Results","text":"The MCMC posterior mean and 95% credible interval match the exact Beta posterior closely, confirming correct implementation. The plot shows the Bayesian update from prior to posterior, with the MCMC histogram overlaid.\n\nprintln(\"Posterior mean:  MCMC = \", round(mean(samples);          digits=4),\n                       \"  exact = \", round(mean(posterior_exact); digits=4))\nprintln(\"95% CI:  MCMC  = [\", round(quantile(samples,         0.025); digits=4),\n                    \", \",      round(quantile(samples,         0.975); digits=4), \"]\")\nprintln(\"         exact = [\", round(quantile(posterior_exact, 0.025); digits=4),\n                    \", \",      round(quantile(posterior_exact, 0.975); digits=4), \"]\")\n\nxgrid = range(0.3, 0.85; length=300)\nhistogram(samples; bins=50, normalize=:pdf, alpha=0.5,\n          label=\"MCMC samples\", xlabel=\"θ\", ylabel=\"Density\",\n          title=\"Coin-flip: prior → posterior\")\nplot!(xgrid, pdf.(prior, xgrid);\n      lw=2, color=:gray, ls=:dash, label=\"Prior Beta($(α_prior),$(β_prior))\")\nplot!(xgrid, pdf.(posterior_exact, xgrid);\n      lw=2, color=:black, label=\"Exact posterior\")\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"generated/house_price_prediction/#Bayesian-Linear-Regression:-House-Price-Prediction","page":"Importance sampling: House Price Prediction","title":"Bayesian Linear Regression: House Price Prediction","text":"We extend the coin-flip pattern to a multivariate problem: inferring the parameters of a linear price model from noisy observations. The same MonteCarloX.jl accept! interface handles the posterior ratio — prior plus likelihood — without any normalizing constant.\n\ny = beta_0 + beta_1 x + varepsilon qquad varepsilon sim mathcalN(0sigma^2)\n\nusing Random, Statistics, Distributions, Plots\nusing MonteCarloX","category":"section"},{"location":"generated/house_price_prediction/#CI-parameters","page":"Importance sampling: House Price Prediction","title":"CI parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_steps  = CI_MODE ? 1_000  : 100_000\nburn_in  = CI_MODE ? 200    : 10_000","category":"section"},{"location":"generated/house_price_prediction/#Synthetic-data","page":"Importance sampling: House Price Prediction","title":"Synthetic data","text":"We generate 50 house prices from a known ground-truth model. Working on a normalized scale improves numerical stability and keeps the prior specification simple and scale-free.\n\nβ0_true, β1_true, σ_true = 50_000.0, 1_500.0, 15_000.0   ## USD, USD/m², USD\n\nrng = MersenneTwister(42)\nn   = 50\nx   = Float64.(rand(rng, 90:460, n))\ny   = β0_true .+ β1_true .* x .+ σ_true .* randn(rng, n)\n\nx_mean, x_std = mean(x), std(x)\ny_mean, y_std = mean(y), std(y)\nx_norm = (x .- x_mean) ./ x_std\ny_norm = (y .- y_mean) ./ y_std\n\nprintln(\"Houses: $(n),  price range: \\$$(round(Int, minimum(y))) – \\$$(round(Int, maximum(y)))\")\nprintln(\"Ground truth: β₀ = $(β0_true),  β₁ = $(β1_true) USD/m²,  σ = $(σ_true) USD\")","category":"section"},{"location":"generated/house_price_prediction/#Model-and-priors","page":"Importance sampling: House Price Prediction","title":"Model and priors","text":"Parameters are estimated on the normalized scale. We use weakly informative Normal priors and sample logsigma to enforce positivity.\n\nprior_β0   = Normal(0, 1)\nprior_β1   = Normal(0, 1)\nprior_logσ = Normal(log(0.5), 1)\n\nfunction loglikelihood(θ)\n    β0, β1, logσ = θ\n    σ = exp(logσ)\n    return -0.5 * sum((y_norm .- (β0 .+ β1 .* x_norm)).^2) / σ^2 - n * logσ\nend\n\nlogprior(θ)     = logpdf(prior_β0, θ[1]) + logpdf(prior_β1, θ[2]) + logpdf(prior_logσ, θ[3])\nlogposterior(θ) = logprior(θ) + loglikelihood(θ)","category":"section"},{"location":"generated/house_price_prediction/#Metropolis-sampling","page":"Importance sampling: House Price Prediction","title":"Metropolis sampling","text":"A coordinate-wise Gaussian random walk proposes new parameter vectors. The three-parameter posterior is explored jointly; accept! evaluates the log-posterior ratio and updates the acceptance counter automatically.\n\nfunction run_metropolis(logposterior; seed=2026, Δ=0.05)\n    rng     = MersenneTwister(seed)\n    alg     = Metropolis(rng, logposterior)\n    θ       = [rand(rng, prior_β0), rand(rng, prior_β1), rand(rng, prior_logσ)]\n    samples = [Float64[] for _ in 1:3]\n    for _ in 1:burn_in\n        θ_new = θ .+ Δ .* randn(rng, 3)\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n    end\n    reset!(alg)\n    for _ in 1:n_steps\n        θ_new = θ .+ Δ .* randn(rng, 3)\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n        push!.(samples, θ)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior)\n\nprintln(\"Step size Δ       : 0.05 (all parameters)\")\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", length(samples[1]))","category":"section"},{"location":"generated/house_price_prediction/#Back-transform-to-SI-units","page":"Importance sampling: House Price Prediction","title":"Back-transform to SI units","text":"Posterior samples on the normalized scale are analytically mapped back to the original units, preserving the full posterior uncertainty.\n\nβ1_si = (y_std / x_std) .* samples[2]\nβ0_si = y_mean .+ y_std .* samples[1] .- β1_si .* x_mean\nσ_si  = y_std .* exp.(samples[3])\n\nfor (name, s, truth, unit) in [\n        (\"β₀\", β0_si, β0_true, \"USD\"),\n        (\"β₁\", β1_si, β1_true, \"USD/m²\"),\n        (\"σ\",  σ_si,  σ_true,  \"USD\")]\n    lo, hi = round.(quantile(s, [0.025, 0.975]); digits=0)\n    println(\"$(name) = $(round(mean(s); digits=1))  [$(lo), $(hi)] $(unit)  (truth: $(truth))\")\nend","category":"section"},{"location":"generated/house_price_prediction/#Posterior-predictive","page":"Importance sampling: House Price Prediction","title":"Posterior predictive","text":"Overlaying 80 randomly drawn regression lines against the data visualises posterior uncertainty. The posterior mean line recovers the ground truth well.\n\nxline   = range(minimum(x), maximum(x); length=200)\nn_lines = min(80, length(β0_si))\nidx     = rand(1:length(β0_si), n_lines)\n\nplt_pred = scatter(x, y; alpha=0.7, ms=4, label=\"data\",\n                   xlabel=\"Area (m²)\", ylabel=\"Price (USD)\",\n                   title=\"Posterior predictive\", size=(700, 320),\n                   margin=5Plots.mm)\nfor i in idx\n    plot!(plt_pred, xline, β0_si[i] .+ β1_si[i] .* xline;\n          lw=1, alpha=0.08, color=:steelblue, label=\"\")\nend\nplot!(plt_pred, xline, mean(β0_si) .+ mean(β1_si) .* xline;\n      lw=2.5, color=:red, label=\"posterior mean\")\nplot!(plt_pred, xline, β0_true .+ β1_true .* xline;\n      lw=2, color=:black, ls=:dash, label=\"ground truth\")","category":"section"},{"location":"generated/house_price_prediction/#Posterior-marginals","page":"Importance sampling: House Price Prediction","title":"Posterior marginals","text":"Diagonal panels show the marginal posterior for each parameter; dashed lines mark the ground truth. All three parameters are well recovered.\n\nfunction marginal_panel(s, truth, xlabel, title; ticks=nothing)\n    p = histogram(s; bins=50, normalize=:pdf, alpha=0.6, label=\"\",\n                  xlabel=xlabel, ylabel=\"\", title=title,\n                  size=(300, 220))\n    ticks !== nothing && plot!(p; xticks=ticks)\n    vline!(p, [truth]; lw=2, ls=:dash, color=:black, label=\"truth\")\n    return p\nend\n\nt3(s) = round.(range(quantile(s, 0.01), quantile(s, 0.99); length=3); digits=0)\n\np_β0 = marginal_panel(β0_si, β0_true, \"β₀ (USD)\",    \"Intercept\"; ticks=t3(β0_si))\np_β1 = marginal_panel(β1_si, β1_true, \"β₁ (USD/m²)\", \"Slope\")\np_σ  = marginal_panel(σ_si,  σ_true,  \"σ (USD)\",     \"Noise\";     ticks=t3(σ_si))\n\nplot(p_β0, p_β1, p_σ; layout=(1,3), size=(900, 260), margin=5Plots.mm)\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"build_your_own_system/#Build-Your-Own-System","page":"Build Your Own System","title":"Build Your Own System","text":"This is the most practical way to start with MonteCarloX.","category":"section"},{"location":"build_your_own_system/#Minimal-goal","page":"Build Your Own System","title":"Minimal goal","text":"To run a custom model with MonteCarloX, you typically need:\n\nA state type (your system)\nA way to evaluate local quantities used by your update\nAn update function that calls MonteCarloX algorithm primitives (accept! or step!)\n\nYou do not need to implement the full framework at once.","category":"section"},{"location":"build_your_own_system/#Core-abstractions-in-practice","page":"Build Your Own System","title":"Core abstractions in practice","text":"When building a model package, these abstractions define responsibilities.","category":"section"},{"location":"build_your_own_system/#AbstractSystem","page":"Build Your Own System","title":"AbstractSystem","text":"Owns:\n\nstate variables\nmodel parameters\nmodel-specific observables (for example energy)\nmodel-specific local update ingredients\n\nShould not own:\n\ngeneric sampling logic","category":"section"},{"location":"build_your_own_system/#AbstractEnsemble","page":"Build Your Own System","title":"AbstractEnsemble","text":"Encodes relative probability for equilibrium sampling. In canonical form,\n\npi(x) = frace^-beta E(x)Z(beta)\n\nup to additive constants in log space.\n\ncanonical ensemble: BoltzmannEnsemble(β)\ngeneralized ensemble: tabulated BinnedObject wrapped by ensemble types\n\nAlgorithms use local log-weight differences, so they remain model-agnostic.","category":"section"},{"location":"build_your_own_system/#AbstractAlgorithm","page":"Build Your Own System","title":"AbstractAlgorithm","text":"Owns sampler state and statistics.\n\nExamples:\n\nMetropolis, Glauber, HeatBath\nMulticanonical, WangLandau\nGillespie\n\nTypical fields include RNG, counters (steps, accepted) and/or simulation time. Update mechanics are model-side functions (for example spin_flip!) that call algorithm primitives (accept!, step!, ...).","category":"section"},{"location":"build_your_own_system/#Example:-minimal-scalar-model-(energy(x))-with-Metropolis","page":"Build Your Own System","title":"Example: minimal scalar model (energy(x)) with Metropolis","text":"using Random\nusing MonteCarloX\n\nenergy(x) = 0.5 * x^2\ndelta_energy(x, x_new) = energy(x_new) - energy(x)\n\nfunction local_update(x::Float64, alg::Metropolis)\n    x_new = x + randn(alg.rng)\n    ΔE = delta_energy(x, x_new)\n    if accept!(alg, ΔE)\n        return x_new\n    end\n    return x\nend\n\nrng = MersenneTwister(42)\nalg = Metropolis(rng; β=1.0)  # uses BoltzmannEnsemble(β)\nx = 0.0\nfor _ in 1:10_000\n    x = local_update(x, alg)\nend\n\nThis is the smallest possible pattern: define energy(x), derive ΔE, and let a framework algorithm (Metropolis) handle acceptance.","category":"section"},{"location":"build_your_own_system/#Checklist-for-importance-sampling-systems","page":"Build Your Own System","title":"Checklist for importance-sampling systems","text":"Define your system state type.\nDefine local proposal/update logic.\nCompute local old/new quantity (or delta) needed by accept!.\nApply state changes only after acceptance.\n\nFor many models, this is enough.","category":"section"},{"location":"build_your_own_system/#Example:-birth-death-system-with-Gillespie","page":"Build Your Own System","title":"Example: birth-death system with Gillespie","text":"using Random\nusing MonteCarloX\n\nmutable struct BirthDeathState <: AbstractSystem\n    n::Int\n    λ::Float64\n    μ::Float64\nend\n\nfunction rates(sys::BirthDeathState, t)\n    birth = sys.λ * sys.n\n    death = sys.μ * sys.n\n    return [birth, death]\nend\n\nfunction apply_event!(sys::BirthDeathState, event)\n    if event == 1\n        sys.n += 1\n    elseif event == 2\n        sys.n = max(0, sys.n - 1)\n    end\n    return nothing\nend\n\nalg = Gillespie(MersenneTwister(7))\nsys = BirthDeathState(25, 0.2, 0.1)\nfor _ in 1:10_000\n    t, event = step!(alg, rates(sys, alg.time))\n    event === nothing && break\n    apply_event!(sys, event)\nend\n\nSame system with callback-style integration:\n\nalg = Gillespie(MersenneTwister(8))\nsys = BirthDeathState(25, 0.2, 0.1)\nadvance!(\n    alg,\n    sys,\n    100.0;\n    rates=(state, t) -> rates(state, t),\n    update!=(state, event, t) -> apply_event!(state, event),\n)","category":"section"},{"location":"build_your_own_system/#Checklist-for-continuous-time-systems","page":"Build Your Own System","title":"Checklist for continuous-time systems","text":"Define state type.\nDefine rates(state, t) that returns event rates.\nDefine event-application logic for sampled event indices.\nUse step! for manual loops or advance! for callback-based loops.","category":"section"},{"location":"build_your_own_system/#Where-Measurements-fit","page":"Build Your Own System","title":"Where Measurements fit","text":"Measurements are optional helpers. You can record observables manually in vectors, or use Measurement/Measurements for scheduling convenience.","category":"section"},{"location":"build_your_own_system/#Real-model-reference","page":"Build Your Own System","title":"Real model reference","text":"For a production-ready system implementation, inspect SpinSystems (for example Ising), where model logic is separated cleanly from MonteCarloX algorithms.","category":"section"},{"location":"build_your_own_system/#Abstractions-API-reference","page":"Build Your Own System","title":"Abstractions API reference","text":"","category":"section"},{"location":"build_your_own_system/#MonteCarloX.AbstractSystem","page":"Build Your Own System","title":"MonteCarloX.AbstractSystem","text":"AbstractSystem\n\nBase type for all systems in MonteCarloX.\n\n\n\n\n\n","category":"type"},{"location":"build_your_own_system/#MonteCarloX.AbstractEnsemble","page":"Build Your Own System","title":"MonteCarloX.AbstractEnsemble","text":"AbstractEnsemble\n\nBase type for all ensemble objects.\n\n\n\n\n\n","category":"type"},{"location":"build_your_own_system/#MonteCarloX.AbstractAlgorithm","page":"Build Your Own System","title":"MonteCarloX.AbstractAlgorithm","text":"AbstractAlgorithm\n\nBase type for all Monte Carlo algorithms.\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#Importance-Sampling-Algorithms","page":"Importance Sampling","title":"Importance Sampling Algorithms","text":"Importance sampling in MonteCarloX is built around local proposals + acceptance rules. The defining feature is a discrete-step update loop (proposal → decision → update).\n\nWhile this is most commonly used for equilibrium sampling, the same machinery can be used in non-equilibrium protocols by changing parameters or target weights over steps.","category":"section"},{"location":"importance_sampling_algorithms/#Mental-model","page":"Importance Sampling","title":"Mental model","text":"Each step is:\n\npropose a local change\ncompute a local log-ratio (or local energy difference)\naccept/reject via the algorithm\nupdate counters and measure if needed\n\nThe core API function is accept!.","category":"section"},{"location":"importance_sampling_algorithms/#Target-distribution-and-acceptance-rule","page":"Importance Sampling","title":"Target distribution and acceptance rule","text":"Let pi(x) be the target density (or mass function) on the state space.\n\nBayesian example:\n\npi(theta) = p(theta mid mathcalD)\n\nStatistical-mechanics microstate example:\n\npi(x) = p(x mid beta) = frace^-beta E(x)Z(beta)\n\nMetropolis-Hastings acceptance is\n\nalpha(x to x) = minleft(1 fracpi(x) q(x mid x)pi(x) q(x mid x)right)\n\nFor symmetric local proposals q, this reduces to pi(x)  pi(x).","category":"section"},{"location":"importance_sampling_algorithms/#Unified-view:-Bayesian-and-statistical-physics-targets","page":"Importance Sampling","title":"Unified view: Bayesian and statistical-physics targets","text":"The same sampler is used in both domains by changing only the callable log target score:\n\nBayesian inference: logweight(theta) = logposterior(theta) = loglikelihood(theta) + logprior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nIn MonteCarloX this callable is carried by the algorithm as the ensemble object, and can also be accessed as logweight(alg).\n\nBoth views are important:\n\nensemble(alg) is the architecture-level object\nlogweight(alg) is the acceptance-rule interpretation\n\nThey refer to the same callable value.","category":"section"},{"location":"importance_sampling_algorithms/#Metropolis","page":"Importance Sampling","title":"Metropolis","text":"","category":"section"},{"location":"importance_sampling_algorithms/#When-to-use-it","page":"Importance Sampling","title":"When to use it","text":"default first choice for equilibrium sampling\nsimple and robust","category":"section"},{"location":"importance_sampling_algorithms/#Acceptance-intuition","page":"Importance Sampling","title":"Acceptance intuition","text":"always accept moves toward larger target weight\naccept less favorable moves with probability exp(log_ratio)","category":"section"},{"location":"importance_sampling_algorithms/#Minimal-usage","page":"Importance Sampling","title":"Minimal usage","text":"using Random\nusing MonteCarloX\n\nrng = MersenneTwister(1)\nlogdensity(x) = -0.5 * x^2\nalg = Metropolis(rng, logdensity)\n\nx = 0.0\nfor _ in 1:20_000\n    x_new = x + randn(alg.rng)\n    x = accept!(alg, x_new, x) ? x_new : x\nend\n\nprintln(acceptance_rate(alg))","category":"section"},{"location":"importance_sampling_algorithms/#Bayesian-example-(primary)","page":"Importance Sampling","title":"Bayesian example (primary)","text":"Coin-flip posterior with local random-walk proposals on theta:\n\npi(theta) = p(theta mid textdata) propto p(textdata mid theta) p(theta)\nimplementation target: logposterior(theta)\n\nRepository example: examples/bayesian_coin_flip.ipynb","category":"section"},{"location":"importance_sampling_algorithms/#Statistical-mechanics-example-(secondary)","page":"Importance Sampling","title":"Statistical-mechanics example (secondary)","text":"Ising microstate sampling:\n\nstate x = spin configuration\ntarget pi(x) = e^-beta E(x)  Z(beta)\nlocal proposal: spin flip\n\nRepository example: examples/spin_systems/metropolis_ising2D.ipynb\n\nEnergy-variable view (same physics):\n\np(E mid beta) = fracOmega(E) e^-beta EZ(beta)\n\nwhere Omega(E) is the density of states.","category":"section"},{"location":"importance_sampling_algorithms/#Glauber","page":"Importance Sampling","title":"Glauber","text":"Same proposal style as Metropolis, but uses logistic acceptance. Useful when that acceptance rule is the natural one for your dynamics or modeling convention.","category":"section"},{"location":"importance_sampling_algorithms/#HeatBath","page":"Importance Sampling","title":"HeatBath","text":"Draws from local conditional probabilities instead of accept/reject. For Ising-like models this often means directly sampling local spin values from conditional weights.","category":"section"},{"location":"importance_sampling_algorithms/#Generalized-ensembles","page":"Importance Sampling","title":"Generalized ensembles","text":"These methods adapt or use non-canonical weights to improve exploration.","category":"section"},{"location":"importance_sampling_algorithms/#Multicanonical","page":"Importance Sampling","title":"Multicanonical","text":"keeps a histogram of visited bins\nupdates tabulated log-weights from histogram information\nuseful for broad energy exploration and barrier crossing\n\nusing Random\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nalg = Multicanonical(MersenneTwister(2), lw)\n\nset!(ensemble(alg), -10:2:10, x -> 0.0)\n# run your update loop with accept!(alg, x_new, x_old)\n# then call update!(ensemble(alg))","category":"section"},{"location":"importance_sampling_algorithms/#Wang-Landau","page":"Importance Sampling","title":"Wang-Landau","text":"updates log-density-of-states estimate at visited bins\nprogressively refines modification factor (logf via update!(ensemble(alg)) between stages)\n\nusing Random\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nalg = WangLandau(MersenneTwister(3), lw; logf=1.0)\n\n# in your loop: accept!(alg, x_new, x_old)\n# between stages: update!(alg)","category":"section"},{"location":"importance_sampling_algorithms/#Choosing-quickly","page":"Importance Sampling","title":"Choosing quickly","text":"Start with Metropolis for standard equilibrium sampling.\nUse HeatBath when conditional local probabilities are natural and cheap.\nUse Multicanonical or WangLandau when canonical sampling gets stuck or explores too narrowly.","category":"section"},{"location":"importance_sampling_algorithms/#Example-map-(algorithm-application)","page":"Importance Sampling","title":"Example map (algorithm ↔ application)","text":"Bayesian scalar posterior (Metropolis): examples/bayesian_coin_flip.ipynb\nBayesian regression posterior (Metropolis): examples/house_price_prediction.ipynb\nCanonical spin sampling (Metropolis): examples/spin_systems/metropolis_ising2D.ipynb\nGeneralized-ensemble exploration (Multicanonical, WangLandau):\nexamples/spin_systems/muca_ising2D.ipynb\nexamples/muca_LDT_gaussian_rngs.ipynb","category":"section"},{"location":"importance_sampling_algorithms/#API-reference","page":"Importance Sampling","title":"API reference","text":"","category":"section"},{"location":"importance_sampling_algorithms/#MonteCarloX.AbstractImportanceSampling","page":"Importance Sampling","title":"MonteCarloX.AbstractImportanceSampling","text":"AbstractImportanceSampling <: AbstractAlgorithm\n\nBase type for importance-sampling algorithms.\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.AbstractMetropolis","page":"Importance Sampling","title":"MonteCarloX.AbstractMetropolis","text":"AbstractMetropolis <: AbstractImportanceSampling\n\nBase type for Metropolis-family samplers where acceptance is naturally computed from a local state difference (e.g. ΔE).\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.AbstractHeatBath","page":"Importance Sampling","title":"MonteCarloX.AbstractHeatBath","text":"AbstractHeatBath <: AbstractAlgorithm\n\nBase type for heat-bath style algorithms.\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.ImportanceSampling","page":"Importance Sampling","title":"MonteCarloX.ImportanceSampling","text":"ImportanceSampling <: AbstractImportanceSampling\n\nGeneric importance-sampling algorithm that operates on full-state acceptance arguments (x_new, x_old) using a callable ensemble.\n\nThe callable may be a function or a log-weight object and should return a scalar score such as a log density / log weight.\n\nConceptual API expectations:\n\nensemble(alg) returns the architectural ensemble object carried by the algorithm.\nlogweight(alg) returns a callable score object/function derived from that ensemble.\nAcceptance logic uses score differences from logweight.\n\nUnified view:\n\nBayesian inference: logweight(theta) = logposterior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nBoth are represented identically as ensemble-provided logweight callables.\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.ensemble-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","title":"MonteCarloX.ensemble","text":"ensemble(alg::AbstractImportanceSampling)\n\nReturn the ensemble object carried by an importance-sampling algorithm.\n\nThis is the canonical accessor in the ensemble-first API. Operationally, this object defines the logweight used in acceptance.\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","title":"MonteCarloX.logweight","text":"logweight(alg::AbstractImportanceSampling)\n\nReturn the algorithm ensemble via a logweight-oriented alias. Equivalent to ensemble(alg).\n\nUse this accessor when reasoning about acceptance formulas.\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractEnsemble}","page":"Importance Sampling","title":"MonteCarloX.logweight","text":"logweight(ens::AbstractEnsemble)\n\nReturn a callable logweight object/function for an ensemble. Concrete ensembles must implement this.\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractEnsemble, Any}","page":"Importance Sampling","title":"MonteCarloX.logweight","text":"logweight(ens::AbstractEnsemble, x)\n\nEvaluate logweight on state/value x. Concrete ensembles should provide this directly or rely on a callable from logweight(ens).\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.Metropolis","page":"Importance Sampling","title":"MonteCarloX.Metropolis","text":"Metropolis <: AbstractMetropolis\n\nMetropolis algorithm for importance sampling.\n\nThe Metropolis algorithm samples from a probability distribution  proportional to exp(log_weight) using an accept/reject criterion.\n\nUnified view:\n\nBayesian inference: logweight(theta) = logposterior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nBoth are passed as the same callable ensemble score. In other words, the algorithm ensemble defines the operative logweight.\n\nFields\n\nrng::AbstractRNG: Random number generator\nensemble: Callable ensemble score (function or weight object)\nsteps::Int: Total number of steps attempted\naccepted::Int: Number of accepted steps\n\nExamples\n\n# Create with Boltzmann weight\nalg = Metropolis(Random.default_rng(), β=2.0)\n\n# Create with Bayesian log-posterior\nlogposterior(theta) = loglikelihood(theta) + logprior(theta)\nalg = Metropolis(Random.default_rng(), logposterior)\n\n# Create with custom callable score\nalg = Metropolis(Random.default_rng(), x -> -0.5 * x^2)\n\n# Create with a weight object\nens = BoltzmannEnsemble(1.5)\nalg = Metropolis(Random.default_rng(), ens)\n\n# Create with a tabulated or custom ensemble\nens = FunctionEnsemble(x -> -0.5 * x^2)\nalg = Metropolis(Random.default_rng(), ens)\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.Glauber","page":"Importance Sampling","title":"MonteCarloX.Glauber","text":"Glauber <: AbstractMetropolis\n\nGlauber sampler with logistic acceptance rule.\n\nUses the same proposal interface and log-ratio as Metropolis-family algorithms, but acceptance is:\n\np_accept = 1 / (1 + exp(-log_ratio))\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.HeatBath","page":"Importance Sampling","title":"MonteCarloX.HeatBath","text":"HeatBath <: AbstractHeatBath\n\nHeat-bath sampler parameters.\n\nFor Ising-like systems, updates draw directly from the local conditional probability using inverse temperature β.\n\n\n\n\n\n","category":"type"},{"location":"importance_sampling_algorithms/#MonteCarloX.accept!","page":"Importance Sampling","title":"MonteCarloX.accept!","text":"accept!(alg::AbstractImportanceSampling, x_new, x_old)\n\nEvaluate acceptance criterion for importance sampling with differences.\n\nUpdates step and acceptance counters in the algorithm. Returns true if the move is accepted based on the Metropolis criterion:\n\nAccept if log_ratio > 0 (new state has higher weight)\nAccept with probability exp(log_ratio) otherwise\n\nThis is the core accept/reject step used by all importance sampling algorithms.\n\n\n\n\n\naccept!(alg::AbstractMetropolis, delta_state)\n\nMetropolis-family acceptance using a local state difference.\n\n\n\n\n\naccept!(alg::ImportanceSampling{<:WangLandauEnsemble}, x_new, x_old)\n\nPerform Metropolis acceptance and apply Wang-Landau local adaptation at the visited state by updating the tabulated logweight.\n\n\n\n\n\n","category":"function"},{"location":"importance_sampling_algorithms/#MonteCarloX.acceptance_rate","page":"Importance Sampling","title":"MonteCarloX.acceptance_rate","text":"acceptance_rate(alg::AbstractImportanceSampling)\n\nCalculate the acceptance rate of the algorithm.\n\nReturns the fraction of accepted moves: accepted/steps. Returns 0.0 if no steps have been attempted yet.\n\n\n\n\n\n","category":"function"},{"location":"importance_sampling_algorithms/#MonteCarloX.reset!-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","title":"MonteCarloX.reset!","text":"reset!(alg::AbstractImportanceSampling)\n\nReset step and acceptance counters to zero.\n\nUseful when you want to measure acceptance rate for a specific run phase without previous history.\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.Multicanonical","page":"Importance Sampling","title":"MonteCarloX.Multicanonical","text":"Multicanonical([rng,] bins; init=0.0)\n\nCreate a generic ImportanceSampling algorithm with a MulticanonicalEnsemble built from bins.\n\nIf rng is not provided, the global RNG will be used.\n\n\n\n\n\nMulticanonical([rng,] ens::MulticanonicalEnsemble)\n\nWrap an existing multicanonical logweight in a generic ImportanceSampling algorithm.\n\nIf rng is not provided, the global RNG will be used.\n\n\n\n\n\n","category":"function"},{"location":"importance_sampling_algorithms/#MonteCarloX.WangLandau","page":"Importance Sampling","title":"MonteCarloX.WangLandau","text":"WangLandau([rng,] bins_or_logweight; init=0.0, logf=1.0)\n\nCreate a generic ImportanceSampling algorithm with a WangLandauEnsemble built from bins_or_logweight. If rng is not provided, the global RNG will be used.\n\n\n\n\n\n","category":"function"},{"location":"importance_sampling_algorithms/#MonteCarloX.update!-Tuple{AbstractEnsemble, Vararg{Any}}","page":"Importance Sampling","title":"MonteCarloX.update!","text":"update!(ens::AbstractEnsemble, args...; kwargs...)\n\nPerform in-place adaptation/update of an ensemble. Concrete ensembles must specialize this when supported.\n\n\n\n\n\n","category":"method"},{"location":"importance_sampling_algorithms/#MonteCarloX.update!-Tuple{WangLandauEnsemble}","page":"Importance Sampling","title":"MonteCarloX.update!","text":"update!(e::WangLandauEnsemble; power=0.5)\n\nUpdate Wang-Landau schedule by scaling the modification factor: logf <- power * logf with default power=0.5.\n\n\n\n\n\n","category":"method"},{"location":"generated/muca_BlumeCapel/#Multicanonical-Sampling-of-the-Blume-Capel-Model","page":"Multicanonical sampling: Blume-Capel","title":"Multicanonical Sampling of the Blume-Capel Model","text":"Illustration of multicanonical sampling in only part of the Hamiltonian. Specifically, the Hamiltonian of the Blume-Capel model reads\n\n   H = -Jsum_ijs_i s_j + Deltasum_i s_i^2\n\nThe spin-spin interaction remains in the canonical (Boltzmann) ensemble while we construct a multicanonical ensemble for the crystal-field term. Depending on the temperature, a change in Delta induces no transition, a second-order, or a first-order phase transition.\n\nusing Random, StatsBase\nusing MonteCarloX, SpinSystems\nusing Plots, ProgressMeter","category":"section"},{"location":"generated/muca_BlumeCapel/#CI-parameters","page":"Multicanonical sampling: Blume-Capel","title":"CI parameters","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nnum_iter           = CI_MODE ? 3       : 20\nthermalization_steps = CI_MODE ? 100   : 10_000\nrecording_steps    = CI_MODE ? 1_000   : 1_000_000;\nnothing #hide","category":"section"},{"location":"generated/muca_BlumeCapel/#Parameters","page":"Multicanonical sampling: Blume-Capel","title":"Parameters","text":"L   = 8\nT   = 0.9\nsys = BlumeCapel([L, L]);\nnothing #hide","category":"section"},{"location":"generated/muca_BlumeCapel/#Custom-ensemble","page":"Multicanonical sampling: Blume-Capel","title":"Custom ensemble","text":"We combine a Boltzmann weight for the pairwise interaction with a multicanonical weight for the crystal-field term sum_i s_i^2. The CustomEnsemble routes each contribution to the appropriate ensemble.\n\nmutable struct CustomEnsemble <: AbstractEnsemble\n    pair          :: BoltzmannEnsemble\n    spin2         :: MulticanonicalEnsemble\n    record_visits :: Bool\nend\n\n@inline function MonteCarloX.logweight(lw::CustomEnsemble, H::Tuple{<:Real,<:Real})\n    return MonteCarloX.logweight(lw.pair, H[1]) + MonteCarloX.logweight(lw.spin2, H[2])\nend\n\n@inline MonteCarloX.should_record_visit(lw::CustomEnsemble) = lw.record_visits\n\n@inline function MonteCarloX.record_visit!(lw::CustomEnsemble, H_vis::Tuple{<:Real,<:Real})\n    MonteCarloX.record_visit!(lw.spin2, H_vis[2])\n    return nothing\nend\n\n@inline function reset_histogram!(lw::CustomEnsemble)\n    fill!(lw.spin2.histogram.values, zero(eltype(lw.spin2.histogram.values)))\n    return nothing\nend\n\n@inline reset_histogram!(alg::AbstractImportanceSampling) =\n    reset_histogram!(MonteCarloX.ensemble(alg))\n\nens = CustomEnsemble(\n    BoltzmannEnsemble(T=T),\n    MulticanonicalEnsemble(0:1:length(sys.spins)),\n    true,\n);\nnothing #hide","category":"section"},{"location":"generated/muca_BlumeCapel/#Spin-flip","page":"Multicanonical sampling: Blume-Capel","title":"Spin flip","text":"We implement a custom spin_flip! for the Blume-Capel model that evaluates the two-component observable (Jsum s_i s_j sum s_i^2) and passes it to accept! as a tuple — the CustomEnsemble routes each component to the correct acceptance weight.\n\nfunction spin_flip!(sys::SpinSystems.AbstractBlumeCapel, alg::AbstractImportanceSampling)\n    i     = pick_site(alg.rng, length(sys.spins))\n    s_new = SpinSystems._propose_state(alg.rng, sys.spins[i])\n    Δpair, Δspin, Δspin2 = SpinSystems.propose_changes(sys, i, s_new)\n    H_old = (sys.J * sys.sum_pair_interactions, sys.sum_spins2)\n    H_new = (H_old[1] + sys.J * Δpair, H_old[2] + Δspin2)\n    accept!(alg, H_new, H_old) && modify!(sys, i, s_new, Δpair, Δspin, Δspin2)\n    return nothing\nend","category":"section"},{"location":"generated/muca_BlumeCapel/#Multicanonical-iteration","page":"Multicanonical sampling: Blume-Capel","title":"Multicanonical iteration","text":"Each iteration thermalizes the system, resets the histogram, accumulates statistics, and updates the multicanonical weights via the Wang-Landau rule.\n\nrng = Xoshiro(42)\nalg = Metropolis(rng, ens)\n\nhistograms = Vector{typeof(ensemble(alg).spin2.histogram)}()\nlogweights = Vector{typeof(ensemble(alg).spin2.logweight)}()\nacceptrate = Float64[]\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:num_iter\n    for _ in 1:thermalization_steps; spin_flip!(sys, alg); end\n    reset!(alg)\n    reset_histogram!(alg)\n    for _ in 1:recording_steps;     spin_flip!(sys, alg); end\n    MonteCarloX.update!(ensemble(alg).spin2)\n    push!(histograms, deepcopy(ensemble(alg).spin2.histogram))\n    push!(logweights, deepcopy(ensemble(alg).spin2.logweight))\n    push!(acceptrate, acceptance_rate(alg))\nend","category":"section"},{"location":"generated/muca_BlumeCapel/#Convergence","page":"Multicanonical sampling: Blume-Capel","title":"Convergence","text":"The acceptance rate should stabilise as the weights converge to flat.\n\nplot(acceptrate; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     label=nothing, size=(600, 220), margin=5Plots.mm, ylims=(0,1))","category":"section"},{"location":"generated/muca_BlumeCapel/#Histograms-and-log-weights","page":"Multicanonical sampling: Blume-Capel","title":"Histograms and log-weights","text":"Each iteration refines the estimated log-DOS for sum_i s_i^2. Converged iterations should show a flat histogram and a smooth log-weight.\n\nfunction plot_histograms_and_logweights(xlabel, hist_vec, lw_vec; title_prefix=\"\")\n    n    = length(hist_vec)\n    cols = palette(:viridis, max(n, 2))[1:n]\n    xs   = get_centers(hist_vec[1])\n    i0   = 1\n\n    p1 = plot(xs, hist_vec[1].values; lw=2, color=cols[1],\n              xlabel=xlabel, ylabel=\"counts\",\n              title=\"$(title_prefix) histograms\", legend=false,\n              ylims=(0, maximum(hist_vec[1].values) * 1.2))\n    for i in 2:n\n        plot!(p1, xs, hist_vec[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=xlabel, ylabel=\"-log w\",\n              title=\"$(title_prefix) log-weights\", legend=false)\n    for i in 1:n\n        plot!(p2, xs, -lw_vec[i].values .+ lw_vec[i].values[i0]; lw=2, color=cols[i])\n    end\n\n    return plot(p1, p2; layout=(@layout([a b])), size=(960, 320), margin=4Plots.mm)\nend\n\nplot_histograms_and_logweights(\"∑sᵢ²\", histograms, logweights; title_prefix=\"MUCA\")\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"generated/eight_schools/#Hierarchical-Bayesian-Inference:-The-Eight-Schools-Problem","page":"Hierarchical sampling: Eight Schools","title":"Hierarchical Bayesian Inference: The Eight Schools Problem","text":"The eight schools problem (Rubin, 1981) is a canonical example of hierarchical Bayesian modelling. A test-preparation program was run independently in 8 schools; each school measured a mean score improvement y_n with standard error sigma_n. The effects vary widely and their standard errors are large — so neither pooling all schools nor treating them independently is appropriate.\n\nThe hierarchical solution: assume each school's true improvement theta_n is drawn from a shared population distribution, so information is partially pooled across schools.\n\ntheta_n sim mathcalN(mu tau) qquad\ny_n sim mathcalN(theta_n sigma_n)\n\nwith priors mu sim mathcalN(0 10) and logtau sim mathcalN(5 1), following the TensorFlow Probability implementation.\n\nusing Random, Statistics, Distributions\nusing StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots","category":"section"},{"location":"generated/eight_schools/#CI-parameters","page":"Hierarchical sampling: Eight Schools","title":"CI parameters","text":"In smoke-test mode (CI) we reduce the number of samples to keep the run fast. Full results require n_burn=10_000, n_samples=100_000.\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_burn    = CI_MODE ? 200     : 10_000\nn_samples = CI_MODE ? 500     : 100_000\nthin      = CI_MODE ? 1       : 10","category":"section"},{"location":"generated/eight_schools/#Data","page":"Hierarchical sampling: Eight Schools","title":"Data","text":"y_schools = [28.0,  8.0, -3.0,  7.0, -1.0,  1.0, 18.0, 12.0]  ## mean score improvements\nσ_schools = [15.0, 10.0, 16.0, 11.0,  9.0, 11.0, 10.0, 18.0]  ## standard errors\nJ         = length(y_schools)\n\nprintln(\"School effects  : \", y_schools)\nprintln(\"Standard errors : \", σ_schools)","category":"section"},{"location":"generated/eight_schools/#Model","page":"Hierarchical sampling: Eight Schools","title":"Model","text":"We sample logtau directly to keep the sampler unconstrained. The prior logtau sim mathcalN(51) is equivalent to a textLogNormal(51) prior on tau — no Jacobian needed.\n\nThe PyMC/Stan canonical version uses tau sim textHalfCauchy(05) instead, which places more mass near zero and favours stronger pooling.\n\nThe full state vector is mu logtau theta_1ldotstheta_8.\n\nget_μ(s)    = s[1]\nget_logτ(s) = s[2]\nget_θ(s)    = s[3:end]\n\nfunction logposterior(s)\n    μ, logτ, θ = get_μ(s), get_logτ(s), get_θ(s)\n    τ   = exp(logτ)\n    lp  = logpdf(Normal(0, 10), μ)                    ## population mean\n    lp += logpdf(Normal(5, 1),  logτ)                 ## log τ ~ N(5,1)\n    lp += sum(logpdf.(Normal(μ, τ), θ))               ## school effects\n    lp += sum(logpdf.(Normal.(θ, σ_schools), y_schools))  ## likelihood\n    return lp\nend\n\ns0 = [mean(y_schools); log(std(y_schools)); copy(y_schools)]\nprintln(\"Initial log-posterior : \", round(logposterior(s0); digits=2))","category":"section"},{"location":"generated/eight_schools/#Metropolis-sampling","page":"Hierarchical sampling: Eight Schools","title":"Metropolis sampling","text":"We update one parameter at a time with a uniform random-walk proposal. Step sizes are tuned separately for (mu logtau) and the school effects theta_n.\n\nfunction update!(s, alg, Δ)\n    i     = rand(alg.rng, 1:length(s))\n    s_new = copy(s)\n    s_new[i] += rand(alg.rng, Uniform(-Δ[i], Δ[i]))\n    accept!(alg, s_new, s) && (s[i] = s_new[i])\nend\n\nfunction run_metropolis(logposterior, s0; seed=42)\n    rng     = Xoshiro(seed)\n    alg     = Metropolis(rng, logposterior)\n    s       = copy(s0)\n    Δ       = vcat([2.0, 2.0], fill(5.0, length(s)-2))\n    samples = zeros(length(s), n_samples)\n    for _ in 1:n_burn\n        update!(s, alg, Δ)\n    end\n    for k in 1:n_samples*thin\n        update!(s, alg, Δ)\n        k % thin == 0 && (samples[:, k÷thin] = s)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior, s0)\n\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", size(samples, 2))","category":"section"},{"location":"generated/eight_schools/#Convergence-check","page":"Hierarchical sampling: Eight Schools","title":"Convergence check","text":"The log-posterior trace should be stationary with no visible trend.\n\nlps = [logposterior(samples[:, i]) for i in 1:size(samples,2)]\nplot(lps; xlabel=\"Iteration\", ylabel=\"Log-posterior\",\n     title=\"Convergence trace\", size=(700, 220),\n     margin=5Plots.mm, legend=false)","category":"section"},{"location":"generated/eight_schools/#Results","page":"Hierarchical sampling: Eight Schools","title":"Results","text":"Posterior medians and 95% credible intervals for all parameters. Partial pooling shrinks extreme school effects toward the population mean mu.\n\nμ_s = samples[1, :]\nτ_s = exp.(samples[2, :])\nθ_s = [samples[2+i, :] for i in 1:J]\n\nprintln(\"Parameter   median     95% CI\")\nprintln(\"─────────────────────────────────────\")\nfor (name, s) in vcat([(\"μ\", μ_s), (\"τ\", τ_s)],\n                      [(\"θ[$(i)]\", θ_s[i]) for i in 1:J])\n    lo, hi = round.(quantile(s, [0.025, 0.975]); digits=1)\n    println(rpad(name, 10), rpad(round(median(s); digits=1), 10),\n            \"[$(lo), $(hi)]\")\nend","category":"section"},{"location":"generated/eight_schools/#Posterior-marginals","page":"Hierarchical sampling: Eight Schools","title":"Posterior marginals","text":"Each panel shows the posterior histogram against the prior curve. The hierarchical prior on theta_n uses the posterior medians of (mu tau) as its parameters, illustrating the learned population distribution.\n\nfunction marginal_panel(s, prior, xlabel)\n    hist = fit(Histogram, s; nbins=40)\n    dist = normalize(hist; mode=:pdf)\n    xs   = range(hist.edges[1][1], hist.edges[1][end]; length=300)\n    fig  = plot(dist; st=:bar, linewidth=0, alpha=0.6,\n                label=\"posterior\", xlabel=xlabel, ylabel=\"density\")\n    plot!(fig, xs, pdf.(prior, xs); lw=2, color=:black, label=\"prior\")\n    return fig\nend\n\nθ_prior = Normal(median(μ_s), median(τ_s))\n\npanels = [\n    marginal_panel(μ_s, Normal(0, 10),   \"μ\"),\n    marginal_panel(τ_s, LogNormal(5, 1), \"τ\"),\n]\nfor i in 1:J\n    push!(panels, marginal_panel(θ_s[i], θ_prior, \"θ[$(i)]\"))\nend\n\nplot(panels...; layout=(2, 5), size=(1100, 380), margin=4Plots.mm,\n     plot_title=\"Posterior marginals vs priors\")\n\n\n\nThis page was generated using Literate.jl.","category":"section"},{"location":"#MonteCarloX.jl","page":"Getting Started","title":"MonteCarloX.jl","text":"MonteCarloX is a compact Julia framework for Monte Carlo sampling. It is built around composable primitives, so algorithms stay reusable across very different models.","category":"section"},{"location":"#What-this-package-gives-you","page":"Getting Started","title":"What this package gives you","text":"Equilibrium samplers (Metropolis, Glauber, HeatBath, Multicanonical, WangLandau)\nContinuous-time samplers (Gillespie)\nMeasurement/scheduling framework (Measurements)\nEnsemble and weight tools (BoltzmannEnsemble, BinnedObject)\nEvent handler backends for event-driven dynamics","category":"section"},{"location":"#Core-idea","page":"Getting Started","title":"Core idea","text":"A simulation needs 3 pieces:\n\nSystem: state and model-specific operations\nWeight/rates: target distribution or transition intensities\nAlgorithm: transition sampler\n\nMeasurements are optional convenience tools for organized observable collection.\n\nThis separation keeps algorithm code model-agnostic.","category":"section"},{"location":"#Reading-path","page":"Getting Started","title":"Reading path","text":"If you are new, read in this order:\n\nMonte Carlo Fundamentals\nImportance Sampling Algorithms\nContinuous-Time Sampling Algorithms\nBuild Your Own System\nSystems\nWeights\nMeasurements","category":"section"},{"location":"#Quick-orientation","page":"Getting Started","title":"Quick orientation","text":"Use importance sampling for discrete-step update protocols (equilibrium or driven/non-equilibrium).\nUse continuous-time sampling when physical/simulation time matters.\nUse companion model packages (for example SpinSystems) for concrete systems.","category":"section"},{"location":"#Scope","page":"Getting Started","title":"Scope","text":"MonteCarloX is the algorithmic core. Concrete model families are intentionally external. This keeps the framework concise and easier to extend.","category":"section"},{"location":"#Related-Julia-packages","page":"Getting Started","title":"Related Julia packages","text":"The Julia ecosystem already has several Monte Carlo packages with different goals and interfaces. If your use case is better served by a domain-specific implementation, these are useful alternatives or complements:\n\nGeneralizedMonteCarlo.jl: generalized-ensemble methods (for example multicanonical and related workflows).\nMonteCarlo.jl: quantum many-body focused Monte Carlo framework.\nCarlo.jl: lattice-model Monte Carlo toolkit with a strong focus on physics applications.\n\nOther related packages (grouped by common use cases):\n\nBayesian inference and MCMC:\n\n- [Turing.jl](https://github.com/TuringLang/Turing.jl)\n- [AbstractMCMC.jl](https://github.com/TuringLang/AbstractMCMC.jl)\n- [AdvancedMH.jl](https://github.com/TuringLang/AdvancedMH.jl)\n- [AdvancedHMC.jl](https://github.com/TuringLang/AdvancedHMC.jl)\n- [DynamicHMC.jl](https://github.com/tpapp/DynamicHMC.jl)\n- [BAT.jl](https://github.com/bat/BAT.jl)\n- [Gen.jl](https://github.com/probcomp/Gen.jl)\n\nMonte Carlo integration and low-discrepancy sampling:\n\n- [Cuba.jl](https://github.com/giordano/Cuba.jl)\n- [QuasiMonteCarlo.jl](https://github.com/SciML/QuasiMonteCarlo.jl)\n- [SpinMC](https://github.com/fbuessen/SpinMC.jl)\n\nUncertainty propagation with particle arithmetic:\n\n- [MonteCarloMeasurements.jl](https://github.com/baggepinnen/MonteCarloMeasurements.jl)\n\nMonteCarloX stays focused on compact, model-agnostic algorithmic building blocks, while these packages offer specialized ecosystems for their target domains.","category":"section"},{"location":"#Random-number-generators","page":"Getting Started","title":"Random number generators","text":"MonteCarloX works with any Julia AbstractRNG.\n\nPrefer Xoshiro as a modern default for new projects.\nUse MersenneTwister when compatibility with existing workflows is needed.\n\nBecause RNG is passed directly to algorithms, changing RNG is a one-line change.","category":"section"},{"location":"measurements/#Measurements","page":"Measurements","title":"Measurements","text":"MonteCarloX separates what you measure from when you measure it. Measurement and Measurements are convenience helpers — they are not required for running MonteCarloX algorithms. You can always collect observables manually in your simulation loop.","category":"section"},{"location":"measurements/#Building-blocks","page":"Measurements","title":"Building blocks","text":"Measurement: one observable paired with one data container\nMeasurements: named collection with a shared schedule\nschedule types:\nIntervalSchedule\nPreallocatedSchedule","category":"section"},{"location":"measurements/#Step-based-measurements-(common-in-equilibrium-loops)","page":"Measurements","title":"Step-based measurements (common in equilibrium loops)","text":"using MonteCarloX\n\nmeasurements = Measurements([\n    :energy        => energy        => Float64[],\n    :magnetization => magnetization => Float64[],\n], interval=10)\n\n# in your loop:\n# measure!(measurements, sys, step)\n\nThis records every 10 loop steps.","category":"section"},{"location":"measurements/#Time-based-measurements-(common-in-Gillespie-loops)","page":"Measurements","title":"Time-based measurements (common in Gillespie loops)","text":"using MonteCarloX\n\ntimes = collect(0.0:0.1:10.0)\nmeasurements = Measurements([\n    :N => (state -> state[:N]) => Float64[],\n], times)\n\n# in your loop:\n# measure!(measurements, state, t)\n# stop criterion: is_complete(measurements)\n\nPreallocatedSchedule handles event skipping by consuming all crossed checkpoints.","category":"section"},{"location":"measurements/#Data-access-and-reset","page":"Measurements","title":"Data access and reset","text":"measurements[:energy].data — raw storage\ndata(measurements, :energy) — convenience accessor\nreset!(measurements) — clears data and restarts schedule state","category":"section"},{"location":"measurements/#API-reference","page":"Measurements","title":"API reference","text":"","category":"section"},{"location":"measurements/#MonteCarloX.Measurement","page":"Measurements","title":"MonteCarloX.Measurement","text":"Measurement{F,T}\n\nA measurement consisting of an observable function and a data container.\n\nFields\n\nobservable::F: Function that extracts a value from the system\ndata::T: Container for storing measurements (Vector, Histogram, etc.)\n\n\n\n\n\n","category":"type"},{"location":"measurements/#MonteCarloX.Measurements","page":"Measurements","title":"MonteCarloX.Measurements","text":"Measurements{K,S<:MeasurementSchedule}\n\nContainer for multiple measurements with a shared schedule.\n\nFields\n\nmeasurements::Dict{K, Measurement}: Dictionary of named measurements\nschedule::S: Measurement schedule\n\n\n\n\n\n","category":"type"},{"location":"measurements/#MonteCarloX.MeasurementSchedule","page":"Measurements","title":"MonteCarloX.MeasurementSchedule","text":"MeasurementSchedule\n\nAbstract type for different measurement scheduling strategies.\n\n\n\n\n\n","category":"type"},{"location":"measurements/#MonteCarloX.IntervalSchedule","page":"Measurements","title":"MonteCarloX.IntervalSchedule","text":"IntervalSchedule <: MeasurementSchedule\n\nSchedule measurements at regular intervals.\n\nFields\n\ninterval::Float64: Time/step interval between measurements\n_checkpoint::Float64: Internal checkpoint for next measurement\n\n\n\n\n\n","category":"type"},{"location":"measurements/#MonteCarloX.PreallocatedSchedule","page":"Measurements","title":"MonteCarloX.PreallocatedSchedule","text":"PreallocatedSchedule <: MeasurementSchedule\n\nSchedule measurements at pre-specified times.\n\nFields\n\ntimes::Vector{Float64}: Sorted vector of measurement times\ncheckpoint_idx::Int: Current index in times vector\n\n\n\n\n\n","category":"type"},{"location":"measurements/#MonteCarloX.measure!","page":"Measurements","title":"MonteCarloX.measure!","text":"measure!(measurement::Measurement, sys; kwargs...)\n\nPerform a single measurement by evaluating the observable on the system and storing the result.\n\n\n\n\n\nmeasure!(measurements::Measurements{K, IntervalSchedule}, sys, t; kwargs...)\n\nPerform measurements at regular intervals (indefinite simulation).\n\n\n\n\n\nmeasure!(measurements::Measurements{K, PreallocatedSchedule}, sys, t; kwargs...)\n\nPerform measurements at preallocated times (handles event skipping).\n\n\n\n\n\nmeasure!(sys, event, t)\n\nObserve system sys at time t before modify!. Default is a no-op.\n\n\n\n\n\n","category":"function"},{"location":"measurements/#MonteCarloX.reset!-Tuple{Measurement}","page":"Measurements","title":"MonteCarloX.reset!","text":"reset!(measurement::Measurement)\n\nReset a single measurement to its initial state by clearing its data container. For histogram-backed measurements this zeros the bin counts while preserving binning.\n\n\n\n\n\n","category":"method"},{"location":"measurements/#MonteCarloX.reset!-Tuple{IntervalSchedule}","page":"Measurements","title":"MonteCarloX.reset!","text":"reset!(schedule::MeasurementSchedule)\n\nReset schedule counters/checkpoints back to their initial state.\n\n\n\n\n\n","category":"method"},{"location":"measurements/#MonteCarloX.reset!-Tuple{Measurements}","page":"Measurements","title":"MonteCarloX.reset!","text":"reset!(measurements::Measurements)\n\nReset all measurement data containers and schedule state in-place.\n\n\n\n\n\n","category":"method"},{"location":"measurements/#MonteCarloX.times-Union{Tuple{Measurements{K, PreallocatedSchedule}}, Tuple{K}} where K","page":"Measurements","title":"MonteCarloX.times","text":"times(m::Measurements)\n\nReturn the measurement time points for preallocated schedules.\n\n\n\n\n\n","category":"method"},{"location":"measurements/#MonteCarloX.data-Union{Tuple{K}, Tuple{Measurements{K}, K}} where K","page":"Measurements","title":"MonteCarloX.data","text":"data(m::Measurements{K}, key::K)\n\nReturn the raw data container for a named measurement.\n\n\n\n\n\n","category":"method"},{"location":"measurements/#MonteCarloX.is_complete","page":"Measurements","title":"MonteCarloX.is_complete","text":"is_complete(m::Measurements)\n\nCheck if all scheduled measurements are complete. Returns false for interval-based schedules (indefinite).\n\n\n\n\n\n","category":"function"},{"location":"generated/gillespie_birth_death/#Birth-Death-Process-with-Gillespie-Algorithm","page":"Birth-Death Process (Gillespie)","title":"Birth-Death Process with Gillespie Algorithm","text":"The linear birth-death process is one of the simplest continuous-time stochastic models in population dynamics. Each individual reproduces at rate lambda and dies at rate mu, giving total propensities\n\nr_textbirth = lambda N qquad r_textdeath = mu N\n\nWhen lambda  mu the population grows on average; when lambda  mu it declines toward extinction; at lambda = mu it performs a critical random walk and will eventually go extinct.\n\nusing Random, StatsBase, Plots\nusing MonteCarloX","category":"section"},{"location":"generated/gillespie_birth_death/#System-definition","page":"Birth-Death Process (Gillespie)","title":"System definition","text":"mutable struct BirthDeathProcess <: AbstractSystem\n    N  :: Int\n    λ  :: Float64\n    μ  :: Float64\n    rates :: Vector{Float64}\n    function BirthDeathProcess(N0, λ, μ)\n        new(N0, λ, μ, [λ*N0, μ*N0])\n    end\nend\n\nMonteCarloX.event_source(sys::BirthDeathProcess) = sys.rates\n\nfunction MonteCarloX.modify!(sys::BirthDeathProcess, event::Int, t)\n    event == 1 ? (sys.N += 1) : (sys.N -= 1)\n    sys.rates[1] = sys.λ * sys.N   ## update in place — src reference stays valid\n    sys.rates[2] = sys.μ * sys.N\n    return nothing\nend","category":"section"},{"location":"generated/gillespie_birth_death/#Single-trajectory","page":"Birth-Death Process (Gillespie)","title":"Single trajectory","text":"We run a single simulation at lambda = 042, mu = 040 — a slightly super-critical regime — and record the population every 0.5 time units. advance! handles the event loop internally, calling measure! before each state update and stopping when the total time is reached or all rates vanish (extinction: N = 0).\n\nsys = BirthDeathProcess(10, 0.42, 0.40)\nalg = Gillespie(MersenneTwister(42))\nT   = 100.0\n\nmeasurements = Measurements(\n    [:population => (s -> s.N) => Float64[]],\n    collect(0.0:0.5:T),\n)\nmeasure!(measurements, sys, alg.time)\n\nadvance!(alg, sys, T;\n    measure! = (sys, event, t) -> measure!(measurements, sys, t),\n)\n\npop = measurements[:population].data\nprintln(\"Final population : $(sys.N)\")\nprintln(\"Total events     : $(alg.steps)\")\nprintln(\"Mean population  : $(round(mean(pop); digits=2))\")\n\nplot(collect(0.0:0.5:T)[1:length(pop)], pop; lw=2, label=\"λ=0.42, μ=0.40\",\n     xlabel=\"Time\", ylabel=\"Population N(t)\",\n     title=\"Single birth-death trajectory\", size=(700, 260), margin=5Plots.mm)","category":"section"},{"location":"generated/gillespie_birth_death/#Comparison-across-birth-rates","page":"Birth-Death Process (Gillespie)","title":"Comparison across birth rates","text":"Varying lambda at fixed mu = 040 illustrates the three regimes. The log scale makes exponential growth and decay linear, and reveals extinction events as trajectories dropping to zero.\n\nfunction run_birth_death(N0, λ, μ, T; seed=1)\n    sys  = BirthDeathProcess(N0, λ, μ)\n    alg  = Gillespie(MersenneTwister(seed))\n    meas = Measurements(\n        [:N => (s -> s.N) => Float64[]],\n        collect(0.0:0.5:T),\n    )\n    measure!(meas, sys, alg.time)\n    advance!(alg, sys, T;\n        measure! = (sys, event, t) -> measure!(meas, sys, t),\n    )\n    measure!(meas, sys, T)\n    return meas\nend\n\nN0     = 10\nμ      = 0.40\nT_plot = 80.0\nλs     = [0.35, 0.40, 0.45, 0.50]\n\np = plot(xlabel=\"Time\", ylabel=\"Population N(t)\",\n         title=\"Birth-death process for varying λ  (μ = $μ)\",\n         legend=:topleft, yscale=:log10,\n         size=(700, 300), margin=5Plots.mm)\n\nfor (i, λ) in enumerate(λs)\n    meas = run_birth_death(N0, λ, μ, T_plot; seed=100+i)\n    t    = MonteCarloX.times(meas)\n    y    = MonteCarloX.data(meas, :N)\n    idx  = y .> 0\n    plot!(p, t[idx], y[idx]; lw=2, label=\"λ = $λ\")\nend\np\n\nThe sub-critical trajectory (lambda = 035) goes extinct early; the super-critical ones (lambda geq 045) grow exponentially. At lambda = mu = 040 the process is critical and drifts slowly.\n\n\n\nThis page was generated using Literate.jl.","category":"section"}]
}
